const SKELETON_SRC="// src/components/Skeleton.jsx\n// Blocs \"squelette\" fa\u00e7on Facebook (shimmer) \u2014 utilis\u00e9s pendant le chargement\n// des pages, \u00e0 la place d'un simple \"Chargement...\".\nexport function SkeletonBlock({ w = '100%', h = 14, r = 8, style = {} }) {\n  return (\n    <div className=\"skeleton-shimmer\" style={{ width: w, height: h, borderRadius: r, ...style }} />\n  );\n}\n\nexport function SkeletonCircle({ size = 40, style = {} }) {\n  return (\n    <div className=\"skeleton-shimmer\" style={{ width: size, height: size, borderRadius: '50%', flexShrink: 0, ...style }} />\n  );\n}\n\n// Squelette d'une publication du fil d'actualit\u00e9s (avatar + lignes + image)\nexport function SkeletonPost() {\n  return (\n    <div className=\"card\" style={{ marginBottom: 12, padding: 14 }}>\n      <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 12 }}>\n        <SkeletonCircle size={40} />\n        <div style={{ flex: 1 }}>\n          <SkeletonBlock w=\"45%\" h={13} style={{ marginBottom: 6 }} />\n          <SkeletonBlock w=\"25%\" h={10} />\n        </div>\n      </div>\n      <SkeletonBlock w=\"90%\" h={12} style={{ marginBottom: 6 }} />\n      <SkeletonBlock w=\"70%\" h={12} style={{ marginBottom: 12 }} />\n      <SkeletonBlock w=\"100%\" h={180} r={12} />\n    </div>\n  );\n}\n\n// Squelette d'une publication seule (page PostDetail)\nexport function SkeletonSinglePost() {\n  return (\n    <div style={{ padding: 14 }}>\n      <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 14 }}>\n        <SkeletonCircle size={44} />\n        <div style={{ flex: 1 }}>\n          <SkeletonBlock w=\"40%\" h={14} style={{ marginBottom: 6 }} />\n          <SkeletonBlock w=\"22%\" h={10} />\n        </div>\n      </div>\n      <SkeletonBlock w=\"95%\" h={13} style={{ marginBottom: 8 }} />\n      <SkeletonBlock w=\"75%\" h={13} style={{ marginBottom: 16 }} />\n      <SkeletonBlock w=\"100%\" h={320} r={14} style={{ marginBottom: 16 }} />\n      <div style={{ display: 'flex', gap: 10, marginBottom: 16 }}>\n        <SkeletonBlock w=\"33%\" h={36} r={18} />\n        <SkeletonBlock w=\"33%\" h={36} r={18} />\n        <SkeletonBlock w=\"33%\" h={36} r={18} />\n      </div>\n      {[0, 1].map((i) => (\n        <div key={i} style={{ display: 'flex', gap: 10, marginBottom: 14 }}>\n          <SkeletonCircle size={34} />\n          <div style={{ flex: 1 }}>\n            <SkeletonBlock w=\"60%\" h={12} style={{ marginBottom: 6 }} />\n            <SkeletonBlock w=\"40%\" h={12} />\n          </div>\n        </div>\n      ))}\n    </div>\n  );\n}\n\n// Squelette d'une page \"canal\" (Artiste / Boutique) : banni\u00e8re, titre,\n// boutons, carte info, galerie horizontale \u2014 correspond au visuel Facebook.\nexport function SkeletonChannelPage() {\n  return (\n    <div style={{ paddingBottom: 20 }}>\n      <div className=\"skeleton-shimmer\" style={{ height: 170, borderRadius: 0 }} />\n      <div style={{ padding: '16px 16px 0' }}>\n        <SkeletonBlock w=\"60%\" h={22} style={{ marginBottom: 8 }} />\n        <SkeletonBlock w=\"35%\" h={13} style={{ marginBottom: 16 }} />\n        <div style={{ display: 'flex', gap: 10, marginBottom: 20 }}>\n          <SkeletonBlock w=\"48%\" h={40} r={20} />\n          <SkeletonBlock w=\"48%\" h={40} r={20} />\n        </div>\n      </div>\n      <div style={{ height: 10, background: '#F0F2F5' }} />\n      <div style={{ padding: 16 }}>\n        <div style={{ background: '#F7F8FA', borderRadius: 14, padding: 16, marginBottom: 20 }}>\n          <SkeletonBlock w=\"70%\" h={14} style={{ marginBottom: 10 }} />\n          <SkeletonBlock w=\"95%\" h={12} style={{ marginBottom: 8 }} />\n          <SkeletonBlock w=\"80%\" h={12} style={{ marginBottom: 8 }} />\n          <SkeletonBlock w=\"55%\" h={12} />\n        </div>\n        <SkeletonBlock w=\"40%\" h={14} style={{ marginBottom: 12 }} />\n        <div style={{ display: 'flex', gap: 10 }}>\n          {[0, 1, 2].map((i) => (\n            <div key={i} style={{ flex: 1 }}>\n              <SkeletonBlock w=\"100%\" h={110} r={12} style={{ marginBottom: 6 }} />\n              <SkeletonBlock w=\"80%\" h={10} />\n            </div>\n          ))}\n        </div>\n      </div>\n      <div style={{ padding: '0 16px' }}>\n        <SkeletonPost />\n      </div>\n    </div>\n  );\n}\n";
const PROFILE_SRC="// src/pages/Profile.jsx\nimport { useState, useEffect, useRef } from 'react';\nimport { useParams, useNavigate } from 'react-router-dom';\nimport {\n  doc, getDoc, updateDoc, collection, query, where,\n  onSnapshot, orderBy, addDoc, serverTimestamp, arrayUnion, arrayRemove, deleteDoc, limit, increment\n} from 'firebase/firestore';\nimport { db } from '../firebase';\nimport { useAuth } from '../context/AuthContext';\nimport { useLang } from '../context/LanguageContext';\nimport { timeAgo } from '../utils/timeAgo';\nimport { isDataSaverOn, subscribeDataSaver } from '../utils/dataSaver';\nimport { downloadMedia } from '../utils/download';\nimport ShareModal from '../components/ShareModal';\nimport { SkeletonChannelPage } from '../components/Skeleton';\nimport ReportModal from '../components/ReportModal';\nimport BoostOrderModal from '../components/BoostOrderModal';\nimport FollowListModal from '../components/FollowListModal';\nimport { useActiveStoryUids } from '../hooks/useActiveStoryUids';\nimport { NeonBriefcase, NeonGraduation, NeonPhone, NeonGlobe, NeonLocation, NeonHome, NeonMic, NeonArchive, NeonClock, NeonLike, NeonComment, NeonShare, NeonStar } from '../components/NeonIcons';\nimport { uploadToTelegram } from '../utils/telegram';\nimport { getChatId } from '../utils/chat';\nimport { sendPushNotification } from '../utils/onesignal';\nimport { v4 as uuidv4 } from 'uuid';\nimport {\n  HiCamera, HiPencil, HiTag, HiChat, HiOutlineHeart,\n  HiShare, HiStar, HiX, HiUserAdd, HiPhotograph, HiVideoCamera,\n  HiDotsVertical, HiTrash, HiLightningBolt, HiDownload, HiPaperAirplane, HiFlag, HiBan,\n  HiReply, HiPhone, HiLocationMarker, HiLink\n} from 'react-icons/hi';\n\nconst REACTIONS = ['\u2764\ufe0f','\ud83d\ude02','\ud83d\ude2e','\ud83d\ude22','\ud83d\ude21'];\nconst FB_REACTIONS = [\n  { emoji:'\u2764\ufe0f', label:\"J'aime\"    },\n  { emoji:'\ud83d\ude02', label:'Haha'      },\n  { emoji:'\ud83d\ude2e', label:'Wouah'     },\n  { emoji:'\ud83d\ude22', label:'Triste'    },\n  { emoji:'\ud83d\ude21', label:'En col\u00e8re' },\n];\n\nfunction VIPBadge() {\n  return <img src='/vip-badge.png' style={{ width:32, height:32, marginLeft:5, verticalAlign:'middle', display:'inline-block', flexShrink:0, objectFit:'contain' }} alt='VIP'/>;\n}\n\nconst TABS = [\n  { key:'posts',  label:'Publications' },\n  { key:'sales',  label:'Ventes'       },\n  { key:'photos', label:'Photos'       },\n  { key:'videos', label:'Vid\u00e9os'       },\n  { key:'amis',   label:'Amis'         },\n];\n\nexport default function Profile() {\n  const { uid }  = useParams();\n  const { currentUser, userProfile, setUserProfile } = useAuth();\n  const activeStoryUids = useActiveStoryUids();\n  const { t }    = useLang();\n  const navigate = useNavigate();\n\n  const isOwn     = !uid || uid === currentUser?.uid;\n  const [profMenu,     setProfMenu]     = useState(false);\n  const [otherMenu,    setOtherMenu]    = useState(false);\n  const [followListOpen, setFollowListOpen] = useState(null); // null | 'followers' | 'following'\n  const [storyArchive, setStoryArchive] = useState(null);   // null | []\n  const [dataSaver, setDataSaverState] = useState(isDataSaverOn());\n  useEffect(() => subscribeDataSaver(setDataSaverState), []);\n  const [shareModalPost, setShareModalPost] = useState(null);\n  const [souvenirs,    setSouvenirs]    = useState(null);   // null | []\n  const targetUid = uid  || currentUser?.uid;\n\n  const [profile,        setProfile]     = useState(null);\n  const [posts,          setPosts]       = useState([]);\n  const [visibleCount,   setVisibleCount] = useState(10);\n  const [activeTab,      setActiveTab]   = useState('posts');\n  const [editing,        setEditing]     = useState(false);\n  const [editForm,       setEditForm]    = useState({\n    fullName:'', bio:'', work:'', study:'', phone:'', website:'',\n    currentCity:'', hometown:'', accountType:'personal',\n  });\n  const [uploadingPhoto, setUploading]   = useState(false);\n  const [coverURL,       setCoverURL]    = useState(null);\n  const [uploadingCover, setUploadCover] = useState(false);\n  const [openCmt,        setOpenCmt]     = useState({});\n  const [cmtText,        setCmtText]     = useState({});\n  const [cmtMedia,       setCmtMedia]    = useState({});\n  const [showReact,      setShowReact]   = useState({});\n  const [reactionModal,  setRM]          = useState(null);\n  const [cmtReactionPicker, setCmtReactionPicker] = useState(null);\n  const [editPost,       setEditPost]    = useState(null);\n  const [editContent,    setEditContent] = useState('');\n  const [postMenu,       setPostMenu]    = useState(null);\n  const [expandedPosts,  setExpandedPosts] = useState({});\n\n  // \u2500\u2500 Menus mikatona rehefa scroll \u2500\u2500\n  useEffect(() => {\n    const close = () => { setPostMenu(null); setShowReact({}); setCmtReactionPicker(null); setProfMenu(false); };\n    window.addEventListener('scroll', close, true);\n    return () => window.removeEventListener('scroll', close, true);\n  }, []);\n\n  // \u2500\u2500 Compteur \"Vues du profil\" (indray mandeha isaky ny session, profil an'olon-kafa) \u2500\u2500\n  useEffect(() => {\n    if (!uid || !currentUser || uid === currentUser.uid) return;\n    const key = 'viewedProfiles';\n    let vs; try { vs = JSON.parse(sessionStorage.getItem(key) || '[]'); } catch { vs = []; }\n    if (vs.includes(uid)) return;\n    try { sessionStorage.setItem(key, JSON.stringify([...vs, uid])); } catch {}\n    updateDoc(doc(db, 'users', uid), { profileViews: increment(1) }).catch(() => {});\n  }, [uid, currentUser]);\n  const [editCmt,        setEditCmt]     = useState(null);\n  const [replyTo,        setReplyTo]     = useState({});\n  const [friendsData,    setFriendsData] = useState([]);\n  const [loadingFriends, setLoadingF]    = useState(false);\n  const [zoomPhoto,      setZoomPhoto]   = useState(null);\n  const [selectedPost,   setSelectedPost] = useState(null);\n  const [reportOpen,     setReportOpen]    = useState(false);\n  const [boostTarget,    setBoostTarget]   = useState(null); // { type, id, ownerUid, title, thumbnailURL }\n  const [friendStatus,   setFriendStatus] = useState('none');\n\n  const photoRef  = useRef();\n  const coverRef  = useRef();\n  const cPhotoRef = useRef({});\n  const cVideoRef = useRef({});\n\n  useEffect(() => {\n    const fn = () => { setPostMenu(null); setOtherMenu(false); };\n    document.addEventListener('click', fn);\n  return () => document.removeEventListener('click', fn);\n  }, []);\n\n  useEffect(() => {\n    if (!targetUid) return;\n    getDoc(doc(db,'users',targetUid)).then(s => {\n      if (s.exists()) {\n        const d = s.data();\n        setProfile(d);\n        setEditForm({\n          fullName: d.fullName || '', bio: d.bio || '',\n          work: d.work || '', study: d.study || '', phone: d.phone || '', website: d.website || '',\n          currentCity: d.currentCity || '', hometown: d.hometown || '', accountType: d.accountType || 'personal',\n        });\n        setCoverURL(d.coverURL || null);\n      }\n    });\n  }, [targetUid]);\n\n  useEffect(() => {\n    if (!targetUid) return;\n    const q = query(collection(db,'posts'), where('uid','==',targetUid), orderBy('createdAt','desc'), limit(60));\n    // \u2705 Les publications d'une page artiste restent sur la page (pas sur le profil perso)\n    return onSnapshot(q, snap => setPosts(snap.docs.map(d=>({id:d.id,...d.data()})).filter(p => !p.artistId && !p.isMusic && !p.shopId && !p.pageId)));\n  }, [targetUid]);\n\n  useEffect(() => {\n    if (!profile||isOwn) return;\n    const f = userProfile?.friends||[], s = userProfile?.sentRequests||[];\n    setFriendStatus(f.includes(targetUid)?'friend':s.includes(targetUid)?'requested':'none');\n  }, [profile, userProfile, targetUid, isOwn]);\n\n  useEffect(() => {\n    if (activeTab!=='amis'||!profile) return;\n    const friends = profile.friends||[];\n    if (!friends.length) { setFriendsData([]); return; }\n    setLoadingF(true);\n    Promise.all(friends.map(fuid => getDoc(doc(db,'users',fuid)).then(s => s.exists()?{uid:fuid,...s.data()}:null)))\n      .then(list => { setFriendsData(list.filter(Boolean)); setLoadingF(false); });\n  }, [activeTab, profile]);\n\n  async function uploadProfilePhoto(e) {\n    const file = e.target.files[0]; if (!file) return;\n    setUploading(true);\n    try {\n      const r = await uploadToTelegram(file);\n      await updateDoc(doc(db,'users',currentUser.uid), { photoURL: r.url });\n      setProfile(p=>({...p,photoURL:r.url})); setUserProfile(p=>({...p,photoURL:r.url}));\n      await addDoc(collection(db,'posts'),{\n        uid:currentUser.uid, authorName:userProfile.fullName,\n        authorPhoto:r.url, authorUsername:userProfile.username,\n        authorIsVip:userProfile.isVip||false,\n        content:'\ud83d\udcf8 a mis \u00e0 jour sa photo de profil',\n        mediaURL:r.url, mediaType:'image',\n        isProfilePhoto:true, reactions:{}, comments:[],\n        createdAt:serverTimestamp(),\n      });\n    } catch(err) { alert('Erreur upload'); }\n    setUploading(false);\n  }\n\n  async function uploadCoverPhoto(e) {\n    const file = e.target.files[0]; if (!file) return;\n    setUploadCover(true);\n    try {\n      const r = await uploadToTelegram(file);\n      await updateDoc(doc(db,'users',currentUser.uid), { coverURL: r.url });\n      setCoverURL(r.url);\n      setProfile(p=>({...p,coverURL:r.url}));\n      // Voatahiry ao amin'ny photos tab\n      await addDoc(collection(db,'posts'), {\n        uid: currentUser.uid,\n        authorName: userProfile.fullName,\n        authorPhoto: userProfile.photoURL||'',\n        authorUsername: userProfile.username,\n        authorIsVip: userProfile.isVip||false,\n        content: 'Photo de couverture',\n        mediaURL: r.url,\n        mediaType: 'image',\n        isCoverPhoto: true,\n        reactions: {},\n        comments: [],\n        createdAt: serverTimestamp(),\n      });\n    } catch(err) { alert('Erreur upload cover'); }\n    setUploadCover(false);\n  }\n\n  async function saveProfile() {\n    if (!editForm.fullName.trim()) return;\n    await updateDoc(doc(db,'users',currentUser.uid), {\n      fullName: editForm.fullName, bio: editForm.bio,\n      work: editForm.work.trim(), study: editForm.study.trim(),\n      phone: editForm.phone.trim(), website: editForm.website.trim(),\n      currentCity: editForm.currentCity.trim(), hometown: editForm.hometown.trim(),\n      accountType: editForm.accountType,\n    });\n    setProfile(p=>({...p,...editForm})); setUserProfile(p=>({...p,...editForm})); setEditing(false);\n  }\n\n  async function cancelFriendRequest() {\n    try {\n      await updateDoc(doc(db,'users',currentUser.uid), { sentRequests: arrayRemove(targetUid) });\n      setUserProfile(p => ({ ...p, sentRequests: (p.sentRequests||[]).filter(id => id !== targetUid) }));\n      setFriendStatus('none');\n    } catch(e) { console.warn(e); }\n  }\n\n  async function sendFriendRequest() {\n    if (!currentUser||!targetUid) return;\n    await addDoc(collection(db,'friendRequests'), { fromUid:currentUser.uid, toUid:targetUid, fromName:userProfile.fullName, fromPhoto:userProfile.photoURL||'', status:'pending', createdAt:serverTimestamp() });\n    await updateDoc(doc(db,'users',currentUser.uid), { sentRequests:arrayUnion(targetUid) });\n    await addDoc(collection(db,'notifications'), { toUid:targetUid, fromUid:currentUser.uid, fromName:userProfile.fullName, fromPhoto:userProfile.photoURL||'', type:'friendRequest', message:`${userProfile.fullName} vous a envoy\u00e9 une demande d'ami`, read:false, createdAt:serverTimestamp() });\n    setFriendStatus('requested');\n  }\n\n  const isBlockedByMe = (userProfile?.blocked || []).includes(targetUid);\n  async function toggleBlockUser() {\n    if (!targetUid || targetUid === currentUser.uid) return;\n    const msg = isBlockedByMe ? `D\u00e9bloquer ${profile.fullName} ?` : `Bloquer ${profile.fullName} ? Vous ne verrez plus ses publications.`;\n    if (!window.confirm(msg)) return;\n    try {\n      await updateDoc(doc(db, 'users', currentUser.uid), {\n        blocked: isBlockedByMe ? arrayRemove(targetUid) : arrayUnion(targetUid),\n      });\n      setUserProfile(p => ({ ...p, blocked: isBlockedByMe ? (p.blocked||[]).filter(u=>u!==targetUid) : [...(p.blocked||[]), targetUid] }));\n      setOtherMenu(false);\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  function copyProfileLink() {\n    setProfMenu(false); setOtherMenu(false);\n    const url = `${window.location.origin}/profile/${targetUid}`;\n    if (navigator.clipboard?.writeText) navigator.clipboard.writeText(url).then(() => alert('Lien copi\u00e9 !'), () => alert(url));\n    else { const el = document.createElement('textarea'); el.value = url; document.body.appendChild(el); el.select(); document.execCommand('copy'); el.remove(); alert('Lien copi\u00e9 !'); }\n  }\n\n  async function reportUser() {\n    setOtherMenu(false);\n    setReportOpen(true);\n  }\n  async function submitReportUser(motif, detail) {\n    try {\n      await addDoc(collection(db, 'reports'), {\n        type: 'user', targetUid, targetName: profile.fullName,\n        reportedBy: currentUser.uid, reportedByName: userProfile.fullName,\n        motif, detail: detail || '',\n        createdAt: serverTimestamp(), status: 'pending',\n      });\n      setReportOpen(false);\n      alert('Signalement envoy\u00e9. Merci.');\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  const isFollowing = (profile?.followers || []).includes(currentUser?.uid);\n  async function toggleFollow() {\n    if (!currentUser || !targetUid || targetUid === currentUser.uid) return;\n    try {\n      await updateDoc(doc(db, 'users', targetUid), {\n        followers: isFollowing ? arrayRemove(currentUser.uid) : arrayUnion(currentUser.uid),\n      });\n      // Miroir ao amin'ny compte-nao ihany koa : mora jerena avy amin'ny fil d'actualit\u00e9s\n      await updateDoc(doc(db, 'users', currentUser.uid), {\n        following: isFollowing ? arrayRemove(targetUid) : arrayUnion(targetUid),\n      });\n      setProfile(p => ({ ...p, followers: isFollowing ? (p.followers || []).filter(u => u !== currentUser.uid) : [...(p.followers || []), currentUser.uid] }));\n      setUserProfile(p => ({ ...p, following: isFollowing ? (p.following || []).filter(u => u !== targetUid) : [...(p.following || []), targetUid] }));\n      if (!isFollowing) {\n        await addDoc(collection(db, 'notifications'), {\n          toUid: targetUid, fromUid: currentUser.uid, fromName: userProfile.fullName, fromPhoto: userProfile.photoURL || '',\n          type: 'general', message: `${userProfile.fullName} s'est abonn\u00e9(e) \u00e0 votre profil`, read: false, createdAt: serverTimestamp(),\n        });\n      }\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  async function reactToPost(postId, emoji) {\n    if (!REACTIONS.includes(emoji)) return;\n    const post = posts.find(p=>p.id===postId); if (!post) return;\n    const reactions = post.reactions||{}, my = reactions[currentUser.uid];\n    if (my===emoji) {\n      const u={...reactions}; delete u[currentUser.uid];\n      await updateDoc(doc(db,'posts',postId),{reactions:u});\n    } else {\n      await updateDoc(doc(db,'posts',postId),{[`reactions.${currentUser.uid}`]:emoji});\n      if (post.uid !== currentUser.uid) {\n        await addDoc(collection(db,'notifications'), {\n          toUid:post.uid, fromUid:currentUser.uid,\n          fromName:userProfile.fullName, fromPhoto:userProfile.photoURL||'',\n          type:'reaction', postId, emoji,\n          message:`${userProfile.fullName} a r\u00e9agi ${emoji} \u00e0 votre publication`,\n          read:false, createdAt:serverTimestamp(),\n        });\n        sendPushNotification({ toExternalId:post.uid, title:userProfile.fullName, message:`a r\u00e9agi ${emoji}`, data:{type:'reaction',postId} });\n      }\n    }\n    setShowReact(p=>({...p,[postId]:false}));\n  }\n\n  async function openReactionModal(post) {\n    const reactions = post.reactions||{};\n    if (!Object.keys(reactions).length) return;\n    const userData = {};\n    await Promise.all(Object.keys(reactions).map(async uid => {\n      try {\n        const s = await getDoc(doc(db,'users',uid));\n        userData[uid] = s.exists() ? { name:s.data().fullName, photo:s.data().photoURL } : { name:uid, photo:'' };\n      } catch { userData[uid] = { name:uid, photo:'' }; }\n    }));\n    setRM({ reactions, userData });\n  }\n\n  async function reactToCmt(postId, cmtId, emoji) {\n    const post = posts.find(p=>p.id===postId); if (!post) return;\n    const updated = post.comments.map(c => {\n      if (c.id !== cmtId) return c;\n      const reactions = c.reactions||{};\n      const my = reactions[currentUser.uid];\n      if (my===emoji) { const u={...reactions}; delete u[currentUser.uid]; return {...c,reactions:u}; }\n      return {...c,reactions:{...reactions,[currentUser.uid]:emoji}};\n    });\n    await updateDoc(doc(db,'posts',postId),{comments:updated});\n    setCmtReactionPicker(null);\n  }\n\n  async function addComment(postId) {\n    const rt = replyTo[postId];\n    const raw = rt ? `@${rt} ${cmtText[postId]||''}` : (cmtText[postId]||'');\n    const text = raw.trim(); const media = cmtMedia[postId];\n    if (!text && !media) return;\n    let mediaURL='', cMT='';\n    if (media) { try { const r=await uploadToTelegram(media.file); mediaURL=r.url; cMT=r.type; } catch {} }\n    const post = posts.find(p=>p.id===postId);\n    const cmt = {\n      id:uuidv4(), uid:currentUser.uid,\n      authorName:userProfile.fullName, authorPhoto:userProfile.photoURL||'',\n      authorIsVip:userProfile.isVip||false,\n      text:text.slice(0,500), mediaURL, mediaType:cMT,\n      createdAt:new Date().toISOString(),\n    };\n    await updateDoc(doc(db,'posts',postId),{comments:arrayUnion(cmt)});\n    setCmtText(p=>({...p,[postId]:''}));\n    setCmtMedia(p=>({...p,[postId]:null}));\n    setReplyTo(p=>({...p,[postId]:null}));\n    if (post && post.uid !== currentUser.uid) {\n      await addDoc(collection(db,'notifications'), {\n        toUid:post.uid, fromUid:currentUser.uid,\n        fromName:userProfile.fullName, fromPhoto:userProfile.photoURL||'',\n        type:'comment', postId,\n        message:`${userProfile.fullName} a comment\u00e9 votre publication`,\n        read:false, createdAt:serverTimestamp(),\n      });\n      sendPushNotification({ toExternalId:post.uid, title:userProfile.fullName, message:text?`a comment\u00e9 : \"${text.slice(0,50)}\"`:' a comment\u00e9', data:{type:'comment',postId} });\n    }\n  }\n\n  async function deleteCmt(postId, cmt) {\n    if (cmt.uid !== currentUser.uid && post.uid !== currentUser.uid) return;\n    if (!window.confirm('Supprimer ce commentaire ?')) return;\n    await updateDoc(doc(db,'posts',postId),{comments:arrayRemove(cmt)});\n  }\n\n  async function saveEditCmt(postId, oldCmt, newText) {\n    if (!newText.trim()) return;\n    const post = posts.find(p=>p.id===postId); if (!post) return;\n    const updated = post.comments.map(c => c.id===oldCmt.id ? {...c,text:newText.trim()} : c);\n    await updateDoc(doc(db,'posts',postId),{comments:updated});\n    setEditCmt(null);\n  }\n\n  async function deletePost(postId) {\n    const post = posts.find(p=>p.id===postId);\n    if (!post || post.uid !== currentUser.uid) return;\n    if (!window.confirm('Supprimer cette publication ?')) return;\n    await deleteDoc(doc(db,'posts',postId));\n  }\n\n  async function saveEditPost() {\n    if (!editContent.trim()||!editPost||editPost.uid!==currentUser.uid) return;\n    await updateDoc(doc(db,'posts',editPost.id),{content:editContent.trim().slice(0,2000)});\n    setEditPost(null);\n  }\n\n  function sharePost(post) {\n    setShareModalPost(post);\n  }\n\n  function countReactions(r={}) {\n    const c={}; Object.values(r).forEach(e=>{c[e]=(c[e]||0)+1;}); return c;\n  }\n\n  const regularPosts = posts.filter(p=>!p.isSale);\n  const salePosts    = posts.filter(p=>p.isSale);\n  const photoPosts   = posts.filter(p=>p.mediaType==='image'&&p.mediaURL);\n  const videoPosts   = posts.filter(p=>p.mediaType==='video'&&p.mediaURL);\n\n  function getTabContent() {\n    if (activeTab==='posts')  return regularPosts;\n    if (activeTab==='sales')  return salePosts;\n    if (activeTab==='photos') return photoPosts;\n    if (activeTab==='videos') return videoPosts;\n    return [];\n  }\n\n  if (!profile) return <SkeletonChannelPage />;\n  const friendCount = profile.friends?.length||0;\n  const profilePhoto = profile.photoURL ? [{ id:'profile-photo', mediaURL:profile.photoURL, isProfilePhoto:true }] : [];\n  const coverPhotoArr = coverURL ? [{ id:'cover-photo', mediaURL:coverURL, isCoverPhoto:true }] : [];\n  const allPhotos = [...coverPhotoArr, ...profilePhoto, ...photoPosts];\n\n  function renderPost(post) {\n    const rc     = countReactions(post.reactions);\n    const myR    = post.reactions?.[currentUser.uid];\n    const total  = Object.keys(post.reactions||{}).length;\n    const isOwnPost = post.uid === currentUser?.uid;\n    const boosted = post.isBoosted && post.boostUntil && new Date(post.boostUntil)>new Date();\n\n    return (\n      <div key={post.id} className=\"card post-card animate-fade\" style={{ marginBottom:14, border:boosted?'1px solid #a855f755':undefined }}>\n        {boosted && (\n          <div style={{ background:'linear-gradient(135deg,#7c3aed18,#a855f718)', borderBottom:'1px solid #a855f733', padding:'5px 14px' }}>\n            <span style={{ fontSize:10, color:'#a855f7', fontWeight:600 }}>\u26a1 Sponsoris\u00e9</span>\n          </div>\n        )}\n\n        <div style={{ padding:'14px 16px 0', display:'flex', alignItems:'center', justifyContent:'space-between' }}>\n          <div style={{ display:'flex', alignItems:'center', gap:10, flex:1, minWidth:0 }}>\n            <img src={profile.photoURL||`https://ui-avatars.com/api/?name=${encodeURIComponent(profile.fullName||'U')}&background=1877F2&color=fff`} alt=\"\" className=\"avatar\" style={{ width:40, height:40, flexShrink:0 }}/>\n            <div style={{ minWidth:0 }}>\n              <p style={{ fontWeight:600, fontSize:14, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{profile.fullName}{profile.isVip&&<VIPBadge/>}</p>\n              <p style={{ fontSize:12, color:'#65676B' }}>@{profile.username} \u00b7 {post.createdAt?timeAgo(post.createdAt):\"\u00c0 l'instant\"}</p>\n            </div>\n          </div>\n\n          <div style={{ display:'flex', alignItems:'center', gap:6, flexShrink:0 }}>\n            {post.isSale && <div style={{ textAlign:'right' }}><span className=\"sale-badge\">{t('sale')}</span><p className=\"price-tag\" style={{ marginTop:2, fontSize:13 }}>{post.price} Ar</p></div>}\n            <div style={{ position:'relative' }} onClick={e=>e.stopPropagation()}>\n              <button onClick={() => setPostMenu(postMenu===post.id?null:post.id)}\n                style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', padding:4, display:'flex', alignItems:'center' }}><HiDotsVertical size={18}/></button>\n              {postMenu===post.id && (\n                <div style={{ position:'absolute', top:'100%', right:0, background:'white', border:'1px solid #E4E6EB', borderRadius:12, boxShadow:'0 4px 20px rgba(0,0,0,.12)', minWidth:170, zIndex:50, overflow:'hidden' }}>\n                  {isOwnPost && <>\n                    <button onClick={() => { setEditPost(post); setEditContent(post.content); setPostMenu(null); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'11px 16px', background:'none', border:'none', cursor:'pointer', color:'#050505', fontSize:14, borderBottom:'1px solid #F0F2F5', fontFamily:'Poppins' }}><HiPencil size={15} color=\"#1877F2\"/> Modifier</button>\n                    <button onClick={() => { setBoostTarget({ type:'post', id: post.id, ownerUid: post.uid, title: (post.content||'').slice(0,60) || 'Votre publication', thumbnailURL: post.mediaURL || '' }); setPostMenu(null); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'11px 16px', background:'none', border:'none', cursor:'pointer', color:'#050505', fontSize:14, borderBottom:'1px solid #F0F2F5', fontFamily:'Poppins' }}><HiLightningBolt size={15} color=\"#a855f7\"/> Booster</button>\n                    <button onClick={() => { deletePost(post.id); setPostMenu(null); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'11px 16px', background:'none', border:'none', cursor:'pointer', color:'#1877F2', fontSize:14, borderBottom:'1px solid #F0F2F5', fontFamily:'Poppins' }}><HiTrash size={15}/> Supprimer</button>\n                  </>}\n                  {post.mediaURL && <button onClick={() => { downloadMedia(post.mediaURL, post.mediaType); setPostMenu(null); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'11px 16px', background:'none', border:'none', cursor:'pointer', color:'#050505', fontSize:14, fontFamily:'Poppins' }}><HiDownload size={15} color=\"#3b82f6\"/> T\u00e9l\u00e9charger</button>}\n                  {!isOwnPost && !post.mediaURL && <div style={{ padding:'10px 16px', color:'#65676B', fontSize:13 }}>Aucune action</div>}\n                </div>\n              )}\n            </div>\n          </div>\n        </div>\n\n        <div style={{ padding:'10px 16px', cursor:'pointer' }} onClick={() => setSelectedPost(post)}>\n          {post.content && (<>\n            {post.textBg ? (\n            <p style={{ background: post.textBg, minHeight:180, display:'flex', alignItems:'center', justifyContent:'center', textAlign:'center', color:'#fff', fontSize:24, fontWeight:800, padding:'24px 18px', lineHeight:1.4, wordBreak:'break-word', whiteSpace:'pre-wrap', margin:0, borderRadius:8 }}>{post.content}</p>\n            ) : (\n            <p style={{ fontSize:15, lineHeight:1.6, wordBreak:'break-word',\n              ...(expandedPosts[post.id] ? {} : { display:'-webkit-box', WebkitLineClamp:2, WebkitBoxOrient:'vertical', overflow:'hidden' }) }}>\n              {post.content}\n            </p>\n            )}\n            {post.content.length > 120 && (\n              <span onClick={e => { e.stopPropagation(); setExpandedPosts(pv => ({ ...pv, [post.id]: !pv[post.id] })); }}\n                style={{ fontSize:13, fontWeight:700, color:'#65676B', cursor:'pointer' }}>\n                {expandedPosts[post.id] ? 'Voir moins' : 'Voir plus'}\n              </span>\n            )}\n          </>)}\n          {post.isSale && (post.contact||post.lieu) && (\n            <div style={{ marginTop:8, display:'flex', flexWrap:'wrap', gap:8 }}>\n              {post.contact && <a href={`tel:${post.contact}`} onClick={e=>e.stopPropagation()} style={{ display:'flex', alignItems:'center', gap:5, background:'#E4E6EB', borderRadius:20, padding:'5px 12px', color:'#1877F2', fontSize:13, fontWeight:600, textDecoration:'none' }}><HiPhone size={13}/>{post.contact}</a>}\n              {post.lieu && <span style={{ display:'flex', alignItems:'center', gap:5, background:'#F0F2F5', borderRadius:20, padding:'5px 12px', color:'#65676B', fontSize:13 }}><HiLocationMarker size={13} color=\"#1877F2\"/>{post.lieu}</span>}\n            </div>\n          )}\n          {post.sharedFrom && (\n            <div onClick={e => { e.stopPropagation(); navigate(`/post/${post.sharedFrom.id}`); }}\n              style={{ marginTop:8, border:'1px solid #E4E6EB', borderRadius:12, overflow:'hidden', cursor:'pointer' }}>\n              <div style={{ display:'flex', alignItems:'center', gap:8, padding:'9px 12px' }}>\n                <img src={post.sharedFrom.authorPhoto||`https://ui-avatars.com/api/?name=${encodeURIComponent(post.sharedFrom.authorName||'U')}&background=1877F2&color=fff`}\n                  alt=\"\" style={{ width:30, height:30, borderRadius:'50%', objectFit:'cover' }}/>\n                <p style={{ fontWeight:700, fontSize:13 }}>{post.sharedFrom.groupName ? `${post.sharedFrom.groupName} \u00b7 ${post.sharedFrom.authorName}` : post.sharedFrom.authorName}</p>\n              </div>\n              {post.sharedFrom.content && <p style={{ padding:'0 12px 8px', fontSize:13, color:'#050505' }}>{post.sharedFrom.content}</p>}\n              {post.sharedFrom.mediaURL && (\n                post.sharedFrom.mediaType === 'image'\n                  ? <img src={post.sharedFrom.mediaURL} alt=\"\" style={{ width:'100%', maxHeight:320, objectFit:'cover', display:'block' }}/>\n                  : <video src={post.sharedFrom.mediaURL} muted playsInline style={{ width:'100%', maxHeight:320, objectFit:'cover', display:'block', background:'#000' }}/>\n              )}\n            </div>\n          )}\n          {post.mediaURL && (\n            <div style={{ marginTop:8 }}>\n              {post.mediaType==='image' ? <img src={post.mediaURL} alt=\"\" style={{ width:'100%', borderRadius:10, maxHeight:350, objectFit:'cover' }}/> : <div onClick={()=>navigate('/reels',{state:{startId:post.id}})} style={{ position:'relative', cursor:'pointer' }}><video src={post.mediaURL} poster={post.thumbURL || undefined} preload={(dataSaver || post.thumbURL) ? 'none' : 'metadata'} style={{ width:'100%', borderRadius:10, maxHeight:350, objectFit:'cover', background:'#000' }} muted playsInline/><div style={{ position:'absolute', inset:0, display:'flex', alignItems:'center', justifyContent:'center' }}><div style={{ width:50, height:50, background:'rgba(0,0,0,0.5)', borderRadius:'50%', display:'flex', alignItems:'center', justifyContent:'center' }}><span style={{ color:'white', fontSize:20 }}>\u25b6</span></div></div></div>}\n            </div>\n          )}\n        </div>\n\n        {(total > 0 || post.comments?.length > 0) && (\n          <div style={{ padding:'0 16px 8px', display:'flex', alignItems:'center', justifyContent:'space-between' }}>\n            <div onClick={() => openReactionModal(post)} style={{ display:'flex', alignItems:'center', gap:4, cursor:'pointer', minHeight:18 }}>\n              {total > 0 && <>\n                <div style={{ display:'flex', gap:3 }}>{Object.entries(rc).slice(0,3).map(([e]) => <span key={e} style={{ fontSize:14, background:'white', borderRadius:'50%', boxShadow:'0 0 0 1.5px white', lineHeight:1 }}>{e}</span>)}</div>\n                <span style={{ fontSize:13, color:'#65676B' }}>{total}</span>\n              </>}\n            </div>\n            {post.comments?.length > 0 && (\n              <span onClick={() => setOpenCmt(p=>({...p,[post.id]:!p[post.id]}))} style={{ fontSize:13, color:'#65676B', cursor:'pointer' }}>\n                {post.comments.length} commentaire{post.comments.length>1?'s':''}\n              </span>\n            )}\n          </div>\n        )}\n\n        <div className='post-actions-row'>\n          <div style={{ position:'relative', flex:1, display:'flex' }}>\n            <button onClick={() => { const m = post.reactions?.[currentUser.uid]; reactToPost(post.id, m || '\u2764\ufe0f'); }}\n              onContextMenu={e => { e.preventDefault(); setShowReact(p=>({...p,[post.id]:!p[post.id]})); }}\n              className={'post-action-btn'+(myR?' active':'')}\n              style={myR ? { color:'#1877F2', fontWeight:700 } : {}}>\n              <NeonLike size={19} color={myR ? '#1877F2' : '#65676B'}/> J'aime\n            </button>\n            {showReact[post.id] && (\n              <div onClick={e=>e.stopPropagation()} style={{ position:'absolute', bottom:'calc(100% + 8px)', left:0, background:'white', borderRadius:20, padding:'10px 8px 6px', display:'flex', gap:4, boxShadow:'0 4px 24px rgba(0,0,0,.18)', zIndex:50, border:'1px solid #E4E6EB', whiteSpace:'nowrap' }}>\n                {FB_REACTIONS.map(r => (\n                  <button key={r.emoji}\n                    onClick={()=>{ reactToPost(post.id, r.emoji); setShowReact(p=>({...p,[post.id]:false})); }}\n                    style={{ background:'none', border:'none', cursor:'pointer', display:'flex', flexDirection:'column', alignItems:'center', gap:3, padding:'0 4px', minWidth:44 }}>\n                    <span style={{ fontSize:28, lineHeight:1, display:'block', transition:'transform .15s' }}\n                      onTouchStart={ev=>ev.currentTarget.style.transform='scale(1.35) translateY(-4px)'}\n                      onTouchEnd={ev=>ev.currentTarget.style.transform='scale(1)'}\n                    >{r.emoji}</span>\n                    <span style={{ fontSize:10, color:'#65676B', fontWeight:600, fontFamily:'Poppins' }}>{r.label}</span>\n                  </button>\n                ))}\n              </div>\n            )}\n          </div>\n          <button onClick={() => setOpenCmt(p=>({...p,[post.id]:!p[post.id]}))} className='post-action-btn'>\n            <NeonComment size={18}/> Commenter\n          </button>\n          <button onClick={() => sharePost(post)} className='post-action-btn'>\n            <NeonShare size={18}/> Partager\n          </button>\n        </div>\n\n        {isOwnPost && !boosted && (\n          <div style={{ padding:'0 16px 12px' }}>\n            <button\n              onClick={() => setBoostTarget({ type:'post', id: post.id, ownerUid: post.uid, title: (post.content||'').slice(0,60) || 'Votre publication', thumbnailURL: post.mediaURL || '' })}\n              style={{ width:'100%', padding:'9px 0', borderRadius:20, border:'none', background:'linear-gradient(135deg,#1B84FF,#1877F2)', color:'white', fontWeight:700, fontSize:13, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', gap:6, fontFamily:'Poppins' }}>\n              <HiLightningBolt size={16}/> Booster la publication\n            </button>\n          </div>\n        )}\n\n        {openCmt[post.id] && (\n          <div style={{ padding:'0 16px 14px', borderTop:'1px solid #E4E6EB' }}>\n            {post.comments?.map(c => (\n              <div key={c.id} style={{ display:'flex', gap:8, marginTop:10 }}>\n                <img src={c.authorPhoto||`https://ui-avatars.com/api/?name=${encodeURIComponent(c.authorName||'U')}&background=1877F2&color=fff`} alt=\"\" className=\"avatar\" style={{ width:30, height:30, flexShrink:0, cursor:'pointer' }} onClick={() => navigate(`/profile/${c.uid}`)}/>\n                <div style={{ flex:1, background:'#F0F2F5', borderRadius:12, padding:'8px 10px' }}>\n                  <span style={{ fontWeight:600, fontSize:13 }}>{c.authorName}{c.authorIsVip&&<VIPBadge/>}{' '}</span>\n                  {c.text&&<span style={{ fontSize:13 }}>{c.text}</span>}\n                  {c.mediaURL&&<div style={{ marginTop:4 }}>{c.mediaType==='image'?<img src={c.mediaURL} alt=\"\" style={{ maxWidth:200, borderRadius:8 }}/>:<video src={c.mediaURL} controls style={{ maxWidth:200, borderRadius:8 }}/>}</div>}\n                  <div style={{ display:'flex', gap:14, marginTop:5, flexWrap:'wrap', fontSize:12, fontWeight:700, color:'#65676B', position:'relative', alignItems:'center' }}>\n                    <span onClick={() => reactToCmt(post.id, c.id, c.reactions?.[currentUser.uid] || '\u2764\ufe0f')} style={{ cursor:'pointer', color: c.reactions?.[currentUser.uid] ? '#FF2D8D' : '#65676B', fontWeight: c.reactions?.[currentUser.uid] ? 700 : 400 }}>\n                      {c.reactions?.[currentUser.uid] && c.reactions[currentUser.uid] !== '\u2764\ufe0f' ? c.reactions[currentUser.uid] + ' ' : ''}J'aime\n                    </span>\n                    <span onClick={() => setCmtReactionPicker(p => p===c.id?null:c.id)} style={{ cursor:'pointer' }}>\ud83d\ude0a</span>\n                    <span onClick={() => setReplyTo(p=>({...p,[post.id]:c.authorName}))} style={{ cursor:'pointer' }}>R\u00e9pondre</span>\n                    {cmtReactionPicker===c.id && <div style={{ display:'flex', gap:6, background:'white', borderRadius:20, padding:'6px 10px', boxShadow:'0 2px 12px rgba(0,0,0,.2)', position:'absolute', bottom:'110%', left:0, zIndex:10, border:'1px solid #E4E6EB' }}>{REACTIONS.map(em=><span key={em} onClick={()=>reactToCmt(post.id,c.id,em)} style={{ fontSize:20, cursor:'pointer' }}>{em}</span>)}</div>}\n                    {c.uid===currentUser.uid && (\n                      <span onClick={() => setEditCmt({ postId:post.id, cmt:c, text:c.text })} style={{ cursor:'pointer' }}>Modifier</span>\n                    )}\n                    {(c.uid===currentUser.uid||post.uid===currentUser.uid) && (\n                      <span onClick={() => deleteCmt(post.id,c)} style={{ cursor:'pointer', color:'#FF2D8D' }}>Supprimer</span>\n                    )}\n                  </div>\n                </div>\n              </div>\n            ))}\n\n            {replyTo[post.id] && (\n              <div style={{ display:'flex', alignItems:'center', gap:6, marginTop:8, background:'#F0F2F5', padding:'6px 10px', borderRadius:10 }}>\n                <HiReply size={14} color=\"#1877F2\"/>\n                <span style={{ fontSize:12, color:'#65676B' }}>R\u00e9pondre \u00e0 <strong>{replyTo[post.id]}</strong></span>\n                <button onClick={() => setReplyTo(p=>({...p,[post.id]:null}))} style={{ marginLeft:'auto', background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={14}/></button>\n              </div>\n            )}\n\n            {cmtMedia[post.id] && (\n              <div style={{ position:'relative', marginTop:8, display:'inline-block' }}>\n                {cmtMedia[post.id].type==='image'?<img src={cmtMedia[post.id].preview} alt=\"\" style={{ maxWidth:150, borderRadius:8 }}/>:<video src={cmtMedia[post.id].preview} style={{ maxWidth:150, borderRadius:8 }}/>}\n                <button onClick={() => setCmtMedia(p=>({...p,[post.id]:null}))} style={{ position:'absolute', top:2, right:2, background:'rgba(0,0,0,.5)', border:'none', borderRadius:'50%', width:20, height:20, cursor:'pointer', color:'white', fontSize:10 }}>\u2715</button>\n              </div>\n            )}\n\n            <div style={{ display:'flex', gap:6, marginTop:10, alignItems:'center' }}>\n              <img src={userProfile?.photoURL||`https://ui-avatars.com/api/?name=${encodeURIComponent(userProfile?.fullName||'U')}&background=1877F2&color=fff`} alt=\"\" className=\"avatar\" style={{ width:30, height:30, flexShrink:0 }}/>\n              <input ref={el=>cPhotoRef.current[post.id]=el} type=\"file\" accept=\"image/jpeg,image/png,image/gif,image/webp\" style={{ display:'none' }} onChange={e=>{const f=e.target.files[0];if(f)setCmtMedia(p=>({...p,[post.id]:{file:f,type:'image',preview:URL.createObjectURL(f)}}));}}/>\n              <input ref={el=>cVideoRef.current[post.id]=el} type=\"file\" accept=\"video/mp4,video/webm,video/quicktime\" style={{ display:'none' }} onChange={e=>{const f=e.target.files[0];if(f)setCmtMedia(p=>({...p,[post.id]:{file:f,type:'video',preview:URL.createObjectURL(f)}}));}}/>\n              <input className=\"input\" placeholder={replyTo[post.id]?`R\u00e9pondre \u00e0 ${replyTo[post.id]}...`:t('writeComment')} value={cmtText[post.id]||''} onChange={e=>setCmtText(p=>({...p,[post.id]:e.target.value}))} onKeyDown={e=>e.key==='Enter'&&addComment(post.id)} style={{ flex:1, padding:'7px 12px', fontSize:13 }} maxLength={500}/>\n              <button onClick={() => cPhotoRef.current[post.id]?.click()} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', padding:4 }}><HiPhotograph size={18}/></button>\n              <button onClick={() => cVideoRef.current[post.id]?.click()} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', padding:4 }}><HiVideoCamera size={18}/></button>\n              <button onClick={() => addComment(post.id)} style={{ background:'linear-gradient(135deg,#FF2D8D,#FF7AB8)', border:'none', borderRadius:'50%', width:32, height:32, cursor:'pointer', color:'white', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>\u27a4</button>\n            </div>\n          </div>\n        )}\n      </div>\n    );\n  }\n\n  // \u2500\u2500 Archive de votre story (stories rehetra, na efa lany 24h aza) \u2500\u2500\n  async function openStoryArchive() {\n    setProfMenu(false); setStoryArchive([]);\n    try {\n      const { getDocs, collection, query, where } = await import('firebase/firestore');\n      const snap = await getDocs(query(collection(db, 'stories'), where('uid', '==', currentUser.uid)));\n      const list = snap.docs.map(d => ({ id: d.id, ...d.data() }));\n      list.sort((a, b) => (b.ts || 0) - (a.ts || 0));\n      setStoryArchive(list);\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); setStoryArchive(null); }\n  }\n\n  async function deleteArchivedStory(st) {\n    if (!window.confirm('Supprimer cette story de l\\'archive ?')) return;\n    try {\n      const { deleteDoc: dd, doc: dc } = await import('firebase/firestore');\n      await dd(dc(db, 'stories', st.id));\n      setStoryArchive(a => (a || []).filter(x => x.id !== st.id));\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  // \u2500\u2500 Souvenirs : publications tamin'ny andro sy volana mitovy, taona lasa \u2500\u2500\n  function openSouvenirs() {\n    setProfMenu(false);\n    const today = new Date();\n    const list = (posts || []).filter(p => {\n      if (!p.createdAt?.toDate) return false;\n      const d = p.createdAt.toDate();\n      return d.getDate() === today.getDate() && d.getMonth() === today.getMonth() && d.getFullYear() < today.getFullYear();\n    });\n    setSouvenirs(list);\n  }\n\n  return (\n    <>\n      {selectedPost && (\n        <div onClick={() => setSelectedPost(null)} style={{\n          position:'fixed', inset:0, background:'rgba(0,0,0,0.88)',\n          zIndex:500, overflowY:'auto', display:'flex',\n          alignItems:'flex-start', justifyContent:'center', padding:'16px 0 60px'\n        }}>\n          <div onClick={e => e.stopPropagation()} style={{\n            background:'white', borderRadius:16, width:'100%',\n            maxWidth:520, margin:'0 12px', overflow:'hidden'\n          }}>\n            <div style={{ padding:'14px 16px', display:'flex', alignItems:'center', gap:10 }}>\n              <img\n                src={profile.photoURL||`https://ui-avatars.com/api/?name=${encodeURIComponent(profile.fullName||'U')}&background=1877F2&color=fff`}\n                alt=\"\" style={{ width:42,height:42,borderRadius:'50%',objectFit:'cover' }}/>\n              <div style={{ flex:1 }}>\n                <p style={{ fontWeight:700,fontSize:14 }}>{profile.fullName}</p>\n                <p style={{ fontSize:12,color:'#65676B' }}>{timeAgo(selectedPost.createdAt)}</p>\n              </div>\n              <button onClick={() => setSelectedPost(null)} style={{\n                background:'#F0F2F5',border:'none',borderRadius:'50%',\n                width:34,height:34,cursor:'pointer',fontSize:20,\n                display:'flex',alignItems:'center',justifyContent:'center'\n              }}>\u2715</button>\n            </div>\n            {selectedPost.content && (\n              selectedPost.textBg\n                ? <div style={{ background:selectedPost.textBg,minHeight:160,display:'flex',alignItems:'center',justifyContent:'center',padding:'24px 20px' }}>\n                    <p style={{ fontSize:22,fontWeight:800,color:'white',textAlign:'center' }}>{selectedPost.content}</p>\n                  </div>\n                : <p style={{ padding:'0 16px 10px',fontSize:15,lineHeight:1.6,wordBreak:'break-word' }}>{selectedPost.content}</p>\n            )}\n            {selectedPost.mediaURL && (\n              selectedPost.mediaType==='image'\n                ? <img src={selectedPost.mediaURL} alt=\"\" style={{ width:'100%',maxHeight:420,objectFit:'contain',background:'#000',display:'block' }}/>\n                : <video src={selectedPost.mediaURL} controls style={{ width:'100%',maxHeight:420,background:'#000',display:'block' }}/>\n            )}\n            {(Object.keys(selectedPost.reactions||{}).length > 0 || (selectedPost.comments||[]).length > 0) && (\n              <div style={{ padding:'8px 16px',display:'flex',justifyContent:'space-between',borderTop:'1px solid #F0F2F5' }}>\n                <span style={{ fontSize:13,color:'#65676B' }}>{Object.keys(selectedPost.reactions||{}).length} r\u00e9action{Object.keys(selectedPost.reactions||{}).length!==1?'s':''}</span>\n                <span style={{ fontSize:13,color:'#65676B' }}>{(selectedPost.comments||[]).length} commentaire{(selectedPost.comments||[]).length!==1?'s':''}</span>\n              </div>\n            )}\n            <div className=\"post-actions-row\">\n              <button onClick={() => reactToPost(selectedPost.id, selectedPost.reactions?.[currentUser.uid] || '\u2764\ufe0f')}\n                className={'post-action-btn'+(selectedPost.reactions?.[currentUser.uid]?' active':'')}>\n                <NeonLike size={19} color={selectedPost.reactions?.[currentUser.uid]?'#FF2D8D':'#65676B'}/> J'aime\n              </button>\n              <button onClick={() => navigate(`/post/${selectedPost.id}`)} className=\"post-action-btn\">\n                <NeonComment size={18}/> Commenter\n              </button>\n              <button onClick={() => sharePost(selectedPost)} className=\"post-action-btn\">\n                <NeonShare size={18}/> Partager\n              </button>\n            </div>\n          </div>\n        </div>\n      )}\n      <div>\n      <div style={{ height:200, background:'linear-gradient(135deg,#1877F2,#63A9FF,#FFB3D9)', position:'relative' }}>\n        {coverURL && <img src={coverURL} alt='cover' onClick={()=>setZoomPhoto(coverURL)} style={{ width:'100%', height:'100%', objectFit:'cover', position:'absolute', inset:0, cursor:'pointer' }}/>}\n        {isOwn && <>\n          <button onClick={()=>coverRef.current.click()} disabled={uploadingCover} style={{ position:'absolute', bottom:10, right:10, background:'#1877F2', border:'2px solid white', borderRadius:'50%', width:32, height:32, cursor:'pointer', color:'white', display:'flex', alignItems:'center', justifyContent:'center', zIndex:2 }}>{uploadingCover?'...':<HiCamera size={16}/>}</button>\n          <input ref={coverRef} type='file' accept='image/*' onChange={uploadCoverPhoto} style={{ display:'none' }}/>\n        </>}\n        <div style={{ position:'absolute', bottom:-55, left:'50%', transform:'translateX(-50%)' }}>\n          <div style={{ position:'relative' }}>\n            <img src={profile.photoURL||`https://ui-avatars.com/api/?name=${encodeURIComponent(profile.fullName)}&background=1877F2&color=fff&size=100`} alt=\"\" className=\"avatar avatar-ring\" onClick={()=>setZoomPhoto(profile.photoURL)} style={{ width:100, height:100, border: activeStoryUids.has(targetUid) ? '4px solid #1877F2' : '4px solid white', boxShadow: activeStoryUids.has(targetUid) ? '0 0 0 3px white, 0 0 0 6px #63A9FF' : 'none', objectFit:'cover', cursor:'pointer' }}/>\n            {isOwn&&<><button onClick={() => photoRef.current.click()} disabled={uploadingPhoto} style={{ position:'absolute', bottom:2, right:2, background:'#1877F2', border:'2px solid white', borderRadius:'50%', width:28, height:28, cursor:'pointer', color:'white', display:'flex', alignItems:'center', justifyContent:'center' }}>{uploadingPhoto?'...':<HiCamera size={14}/>}</button><input ref={photoRef} type=\"file\" accept=\"image/*\" onChange={uploadProfilePhoto} style={{ display:'none' }}/></>}\n          </div>\n        </div>\n      </div>\n\n      <div style={{ textAlign:'center', padding:'65px 20px 16px' }}>\n        {editing ? (\n          <div style={{ maxWidth:300, margin:'0 auto' }}>\n            <input className=\"input\" value={editForm.fullName} onChange={e=>setEditForm(p=>({...p,fullName:e.target.value}))} style={{ marginBottom:10 }} placeholder={t('fullName')}/>\n            <textarea className=\"input\" value={editForm.bio} onChange={e=>setEditForm(p=>({...p,bio:e.target.value}))} placeholder={t('bio')} rows={2} style={{ resize:'none', marginBottom:10 }}/>\n\n            <p style={{ fontSize:11, fontWeight:700, color:'#65676B', textAlign:'left', margin:'6px 0 6px' }}>INFORMATIONS</p>\n            <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:8 }}><NeonBriefcase/><input className=\"input\" value={editForm.work} onChange={e=>setEditForm(p=>({...p,work:e.target.value}))} placeholder=\"Travail (ex : D\u00e9veloppeur chez Trengo)\" style={{ flex:1 }}/></div>\n            <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:8 }}><NeonGraduation/><input className=\"input\" value={editForm.study} onChange={e=>setEditForm(p=>({...p,study:e.target.value}))} placeholder=\"\u00c9tudes (ex : Universit\u00e9 d'Antananarivo)\" style={{ flex:1 }}/></div>\n            <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:8 }}><NeonLocation/><input className=\"input\" value={editForm.currentCity} onChange={e=>setEditForm(p=>({...p,currentCity:e.target.value}))} placeholder=\"Ville actuelle\" style={{ flex:1 }}/></div>\n            <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:8 }}><NeonHome/><input className=\"input\" value={editForm.hometown} onChange={e=>setEditForm(p=>({...p,hometown:e.target.value}))} placeholder=\"Ville d'origine\" style={{ flex:1 }}/></div>\n            <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:8 }}><NeonPhone/><input className=\"input\" value={editForm.phone} onChange={e=>setEditForm(p=>({...p,phone:e.target.value}))} placeholder=\"Num\u00e9ro de t\u00e9l\u00e9phone\" style={{ flex:1 }}/></div>\n            <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:10 }}><NeonGlobe/><input className=\"input\" value={editForm.website} onChange={e=>setEditForm(p=>({...p,website:e.target.value}))} placeholder=\"Site web\" style={{ flex:1 }}/></div>\n            <div style={{ display:'flex', gap:10 }}>\n              <button className=\"btn-secondary\" onClick={() => setEditing(false)} style={{ flex:1 }}>{t('cancel')}</button>\n              <button className=\"btn-primary\" onClick={saveProfile} style={{ flex:1 }}>{t('save')}</button>\n            </div>\n            <div onClick={() => navigate('/vip')} style={{ marginTop:12, padding:'10px 16px', background:'linear-gradient(135deg,#fef3c7,#fde68a)', borderRadius:12, cursor:'pointer', display:'flex', alignItems:'center', gap:8, border:'1px solid #fcd34d' }}>\n              <HiStar size={18} color=\"#f59e0b\"/>\n              <div style={{ textAlign:'left' }}><p style={{ fontWeight:700, fontSize:13, color:'#92400e' }}>Compte VIP</p><p style={{ fontSize:11, color:'#a16207' }}>Cliquez pour en savoir plus</p></div>\n              {profile.isVip&&<span style={{ marginLeft:'auto', background:'#1877F2', color:'white', fontSize:10, padding:'2px 6px', borderRadius:6, fontWeight:700 }}>ACTIF</span>}\n            </div>\n          </div>\n        ) : (\n          <>\n            <h2 style={{ fontWeight:700, fontSize:20, display:'flex', alignItems:'center', justifyContent:'center', gap:6 }}>\n              {profile.fullName}{profile.isVip&&<VIPBadge/>}\n              {profile.accountType === 'artist' && (\n                <span style={{ display:'inline-flex', alignItems:'center', gap:4, background:'linear-gradient(135deg,#FF6FA5,#FF2D8D)', color:'white', fontSize:11, fontWeight:800, borderRadius:10, padding:'2px 9px' }}>\n                  <NeonMic size={11} color=\"white\"/> ARTISTE\n                </span>\n              )}\n            </h2>\n            <p style={{ color:'#65676B', fontSize:14 }}>@{profile.username}</p>\n            {profile.bio&&<p style={{ marginTop:8, fontSize:14, color:'#65676B', maxWidth:280, margin:'8px auto 0' }}>{profile.bio}</p>}\n\n            {/* \u2500\u2500 Informations compl\u00e8tes (format Facebook) \u2500\u2500 */}\n            {(profile.work || profile.study || profile.currentCity || profile.hometown || profile.phone || profile.website) && (\n              <div style={{ maxWidth:320, margin:'14px auto 0', textAlign:'left', display:'flex', flexDirection:'column', gap:9 }}>\n                {profile.work && <p style={{ fontSize:13, display:'flex', alignItems:'center', gap:9 }}><NeonBriefcase/> Travaille chez <strong>{profile.work}</strong></p>}\n                {profile.study && <p style={{ fontSize:13, display:'flex', alignItems:'center', gap:9 }}><NeonGraduation/> A \u00e9tudi\u00e9 \u00e0 <strong>{profile.study}</strong></p>}\n                {profile.currentCity && <p style={{ fontSize:13, display:'flex', alignItems:'center', gap:9 }}><NeonLocation/> Vit \u00e0 <strong>{profile.currentCity}</strong></p>}\n                {profile.hometown && <p style={{ fontSize:13, display:'flex', alignItems:'center', gap:9 }}><NeonHome/> Originaire de <strong>{profile.hometown}</strong></p>}\n                {profile.phone && <p style={{ fontSize:13, display:'flex', alignItems:'center', gap:9 }}><NeonPhone/> {profile.phone}</p>}\n                {profile.website && <p style={{ fontSize:13, display:'flex', alignItems:'center', gap:9 }}><NeonGlobe/> <a href={profile.website.startsWith('http')?profile.website:`https://${profile.website}`} target=\"_blank\" rel=\"noreferrer\" style={{ color:'#1877F2', textDecoration:'none' }}>{profile.website}</a></p>}\n              </div>\n            )}\n            <div style={{ display:'flex', justifyContent:'center', gap:24, marginTop:16 }}>\n              {[\n                { label:'Publications', value:regularPosts.length },\n                { label:'Ventes', value:salePosts.length },\n                { label:'Amis', value:friendCount, onClick:()=>setActiveTab('amis') },\n                { label:'Abonn\u00e9s', value:(profile.followers||[]).length, onClick:()=>(profile.followers||[]).length>0&&setFollowListOpen('followers') },\n                { label:'Suivi(e)s', value:(profile.following||[]).length, onClick:()=>(profile.following||[]).length>0&&setFollowListOpen('following') },\n              ].map(({label,value,onClick}) => (\n                <div key={label} style={{ textAlign:'center', cursor:onClick?'pointer':'default' }} onClick={onClick}>\n                  <p style={{ fontWeight:700, fontSize:20, color:'#1877F2' }}>{value}</p>\n                  <p style={{ fontSize:11, color:'#65676B' }}>{label}</p>\n                </div>\n              ))}\n            </div>\n            <div style={{ display:'flex', justifyContent:'center', alignItems:'center', flexWrap:'wrap', rowGap:8, gap:10, marginTop:14 }}>\n              {isOwn ? (\n                <>\n                <button onClick={() => setEditing(true)} style={{ display:'inline-flex', alignItems:'center', gap:6, background:\"linear-gradient(180deg,#1B84FF,#1877F2)\", border:\"none\", borderRadius:20, padding:'8px 18px', color:\"white\", fontWeight:600, cursor:'pointer', fontSize:13, boxShadow:\"0 3px 12px rgba(24,119,242,.35)\" }}><HiPencil size={14}/>{t('editProfile')}</button>\n                <button onClick={() => setBoostTarget({ type:'profile', id: currentUser.uid, ownerUid: currentUser.uid, title: profile.fullName || 'Mon profil', thumbnailURL: profile.photoURL || '' })}\n                  style={{ display:'inline-flex', alignItems:'center', gap:6, background:'linear-gradient(135deg,#1B84FF,#1877F2)', border:'none', borderRadius:20, padding:'8px 16px', color:'white', fontWeight:700, cursor:'pointer', fontSize:13, fontFamily:'Poppins' }}>\n                  <HiLightningBolt size={14}/> Booster mon profil\n                </button>\n                <div style={{ position:'relative', display:'inline-block' }} onClick={e => e.stopPropagation()}>\n                  <button onClick={() => setProfMenu(p => !p)} style={{ width:36, height:36, borderRadius:'50%', background:'#F0F2F5', border:'none', cursor:'pointer', color:'#050505', display:'flex', alignItems:'center', justifyContent:'center' }}><HiDotsVertical size={17}/></button>\n                  {profMenu && (\n                    <div style={{ position:'absolute', top:'110%', right:0, background:'white', border:'1px solid #E4E6EB', borderRadius:12, boxShadow:'0 4px 20px rgba(0,0,0,.14)', minWidth:210, zIndex:60, overflow:'hidden' }}>\n                      <button onClick={openStoryArchive} style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'12px 16px', background:'none', border:'none', cursor:'pointer', fontFamily:'Poppins', fontSize:14, fontWeight:400, color:'#050505', borderBottom:'1px solid #F0F2F5', whiteSpace:'nowrap' }}><NeonArchive/> Archive</button>\n                      <button onClick={openSouvenirs} style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'12px 16px', background:'none', border:'none', cursor:'pointer', fontFamily:'Poppins', fontSize:14, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><NeonClock/> Souvenirs</button>\n                      <button onClick={copyProfileLink} style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'12px 16px', background:'none', border:'none', cursor:'pointer', fontFamily:'Poppins', fontSize:14, color:'#050505' }}><HiLink size={16} color=\"#12A48D\"/> Copier le lien</button>\n                    </div>\n                  )}\n                </div>\n                </>\n              ) : (\n                <>\n                  <button onClick={toggleFollow} className={isFollowing ? 'btn-secondary' : 'btn-gold'} style={{ fontSize:13, padding:'0 16px', height:36, display:'inline-flex', alignItems:'center', justifyContent:'center' }}>\n                    {isFollowing ? '\u2713 Abonn\u00e9' : <><NeonStar size={13} color=\"#4A3400\"/> Suivre</>}\n                  </button>\n                  <button onClick={() => navigate(`/messages/${getChatId(currentUser.uid,targetUid)}`)} className=\"btn-primary\" style={{ fontSize:13, padding:'0 18px', height:36, display:'inline-flex', alignItems:'center', justifyContent:'center' }}><HiPaperAirplane size={14} style={{ marginRight:4 }}/>Message</button>\n                  {friendStatus==='none'&&<button onClick={sendFriendRequest} style={{ display:'inline-flex', alignItems:'center', justifyContent:'center', gap:6, background:\"linear-gradient(180deg,#1B84FF,#1877F2)\", border:\"none\", borderRadius:20, padding:'0 16px', height:36, color:\"white\", fontWeight:600, cursor:'pointer', fontSize:13, boxShadow:\"0 3px 12px rgba(24,119,242,.35)\" }}><HiUserAdd size={14}/>Ajouter</button>}\n                  {friendStatus==='requested'&&<button onClick={cancelFriendRequest} style={{ display:'inline-flex', alignItems:'center', justifyContent:'center', background:'#F3F4F6', border:'none', borderRadius:20, padding:'0 16px', height:36, color:'#65676B', fontSize:13, fontWeight:600, cursor:'pointer', fontFamily:'Poppins' }}>Annul\u00e9</button>}\n                  {friendStatus==='friend'&&<span style={{ display:'inline-flex', alignItems:'center', justifyContent:'center', background:'#D1FAE5', borderRadius:20, padding:'0 16px', height:36, color:'#065F46', fontSize:13, fontWeight:600 }}>\u2713 Ami</span>}\n                  <div style={{ position:'relative', display:'inline-block' }} onClick={e => e.stopPropagation()}>\n                    <button onClick={() => setOtherMenu(p => !p)} style={{ width:36, height:36, borderRadius:'50%', background:'#F0F2F5', border:'none', cursor:'pointer', color:'#050505', display:'flex', alignItems:'center', justifyContent:'center' }}><HiDotsVertical size={17}/></button>\n                    {otherMenu && (\n                      <div style={{ position:'absolute', top:'110%', right:0, background:'white', border:'1px solid #E4E6EB', borderRadius:12, boxShadow:'0 4px 20px rgba(0,0,0,.14)', minWidth:210, zIndex:60, overflow:'hidden' }}>\n                        <button onClick={copyProfileLink} style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'12px 16px', background:'none', border:'none', cursor:'pointer', fontFamily:'Poppins', fontSize:14, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiLink size={16} color=\"#12A48D\"/> Copier le lien</button>\n                        <button onClick={reportUser} style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'12px 16px', background:'none', border:'none', cursor:'pointer', fontFamily:'Poppins', fontSize:14, color:'#050505', borderBottom:'1px solid #F0F2F5' }}><HiFlag size={16} color=\"#F2B300\"/> Signaler \u00e0 l'admin</button>\n                        <button onClick={toggleBlockUser} style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'12px 16px', background:'none', border:'none', cursor:'pointer', fontFamily:'Poppins', fontSize:14, color:'#FF2D8D' }}><HiBan size={16}/> {isBlockedByMe ? 'D\u00e9bloquer' : 'Bloquer'} cette personne</button>\n                      </div>\n                    )}\n                  </div>\n                </>\n              )}\n            </div>\n          </>\n        )}\n      </div>\n\n      <div style={{ display:'flex', borderTop:'1px solid #E4E6EB', borderBottom:'1px solid #E4E6EB', background:'white', overflowX:'auto', scrollbarWidth:'none' }}>\n        {TABS.map(tab => (\n          <button key={tab.key} onClick={() => setActiveTab(tab.key)}\n            style={{ flexShrink:0, padding:'12px 16px', border:'none', background:'none', cursor:'pointer',\n              fontWeight:activeTab===tab.key?700:400, color:activeTab===tab.key?'#1877F2':'#65676B',\n              borderBottom:activeTab===tab.key?'2px solid #1877F2':'2px solid transparent',\n              fontSize:13, fontFamily:'Poppins' }}>\n            {tab.label}\n          </button>\n        ))}\n      </div>\n\n      {zoomPhoto && (\n        <div onClick={()=>setZoomPhoto(null)} style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.95)', zIndex:300, display:'flex', alignItems:'center', justifyContent:'center' }}>\n          <img src={zoomPhoto} alt='' style={{ maxWidth:'100%', maxHeight:'100%', objectFit:'contain' }}/>\n          <button onClick={()=>setZoomPhoto(null)} style={{ position:'absolute', top:16, right:16, background:'none', border:'none', color:'white', fontSize:28, cursor:'pointer' }}>\u2715</button>\n        </div>\n      )}\n\n      {editPost && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.5)', zIndex:200, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>\n          <div className=\"card\" style={{ width:'100%', maxWidth:400, padding:20 }}>\n            <h3 style={{ marginBottom:12 }}>Modifier la publication</h3>\n            <textarea className=\"input\" rows={4} value={editContent} onChange={e=>setEditContent(e.target.value)} style={{ resize:'none' }} maxLength={2000}/>\n            <div style={{ display:'flex', gap:10, marginTop:12 }}>\n              <button className=\"btn-secondary\" onClick={() => setEditPost(null)} style={{ flex:1 }}>{t('cancel')}</button>\n              <button className=\"btn-primary\" onClick={saveEditPost} style={{ flex:1 }}>{t('save')}</button>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {editCmt && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.5)', zIndex:200, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>\n          <div className=\"card\" style={{ width:'100%', maxWidth:400, padding:20 }}>\n            <h3 style={{ marginBottom:12 }}>Modifier le commentaire</h3>\n            <textarea className=\"input\" rows={3} value={editCmt.text} onChange={e=>setEditCmt(p=>({...p,text:e.target.value}))} style={{ resize:'none' }} maxLength={500}/>\n            <div style={{ display:'flex', gap:10, marginTop:12 }}>\n              <button className=\"btn-secondary\" onClick={() => setEditCmt(null)} style={{ flex:1 }}>{t('cancel')}</button>\n              <button className=\"btn-primary\" onClick={() => saveEditCmt(editCmt.postId, editCmt.cmt, editCmt.text)} style={{ flex:1 }}>{t('save')}</button>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {reactionModal && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.5)', zIndex:200, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>\n          <div className=\"card\" style={{ width:'100%', maxWidth:360, padding:20, maxHeight:'70vh', overflowY:'auto' }}>\n            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>\n              <h3 style={{ color:'#1877F2', fontWeight:700 }}>R\u00e9actions</h3>\n              <button onClick={() => setRM(null)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={20}/></button>\n            </div>\n            {Object.entries(reactionModal.reactions).map(([uid, emoji]) => {\n              const info = reactionModal.userData?.[uid]||{};\n              return (\n                <div key={uid} onClick={() => { setRM(null); navigate(`/profile/${uid}`); }}\n                  style={{ display:'flex', alignItems:'center', gap:10, padding:'8px 0', borderBottom:'1px solid #E4E6EB', cursor:'pointer' }}>\n                  <img src={info.photo||`https://ui-avatars.com/api/?name=${encodeURIComponent(info.name||'U')}&background=1877F2&color=fff`} alt=\"\" style={{ width:36, height:36, borderRadius:'50%', objectFit:'cover' }}/>\n                  <p style={{ fontSize:14, fontWeight:600, flex:1 }}>{uid===currentUser.uid?'Vous':(info.name||uid)}</p>\n                  <span style={{ fontSize:20 }}>{emoji}</span>\n                </div>\n              );\n            })}\n          </div>\n        </div>\n      )}\n\n      <div style={{ padding:12 }}>\n        {activeTab==='photos'&&(photoPosts.length===0\n          ? <div style={{ textAlign:'center', padding:40, color:'#65676B' }}>Aucune photo</div>\n          : <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:4 }}>\n              {allPhotos.map(p => <div key={p.id} onClick={() => p.isProfilePhoto||p.isCoverPhoto ? setZoomPhoto(p.mediaURL) : navigate(`/post/${p.id}`)} style={{ aspectRatio:'1', overflow:'hidden', borderRadius:8, cursor:'pointer' }}><img src={p.mediaURL} alt=\"\" style={{ width:'100%', height:'100%', objectFit:'cover' }}/></div>)}\n            </div>\n        )}\n\n        {activeTab==='videos'&&(videoPosts.length===0\n          ? <div style={{ textAlign:'center', padding:40, color:'#65676B' }}>Aucune vid\u00e9o</div>\n          : <div style={{ display:'grid', gridTemplateColumns:'repeat(2,1fr)', gap:8 }}>\n              {videoPosts.map(p => (\n                <div key={p.id} onClick={() => navigate(`/post/${p.id}`)} style={{ aspectRatio:'9/16', overflow:'hidden', borderRadius:10, cursor:'pointer', position:'relative' }}>\n                  <video src={p.mediaURL} style={{ width:'100%', height:'100%', objectFit:'cover' }} muted playsInline/>\n                  <div style={{ position:'absolute', inset:0, display:'flex', alignItems:'center', justifyContent:'center' }}>\n                    <div style={{ width:40, height:40, background:'rgba(0,0,0,.5)', borderRadius:'50%', display:'flex', alignItems:'center', justifyContent:'center' }}><span style={{ color:'white', fontSize:16 }}>\u25b6</span></div>\n                  </div>\n                </div>\n              ))}\n            </div>\n        )}\n\n        {activeTab==='amis'&&(\n          loadingFriends ? <div style={{ textAlign:'center', padding:30, color:'#65676B' }}>{t('loading')}</div>\n          : friendsData.length===0 ? <div style={{ textAlign:'center', padding:40, color:'#65676B' }}>Aucun ami pour le moment</div>\n          : <div style={{ display:'grid', gridTemplateColumns:'repeat(2,1fr)', gap:10 }}>\n              {friendsData.map(f => (\n                <div key={f.uid} onClick={() => navigate(`/profile/${f.uid}`)} className=\"card\"\n                  style={{ padding:14, display:'flex', flexDirection:'column', alignItems:'center', gap:8, cursor:'pointer', textAlign:'center' }}>\n                  <img src={f.photoURL||`https://ui-avatars.com/api/?name=${encodeURIComponent(f.fullName||'U')}&background=1877F2&color=fff`} alt=\"\" style={{ width:60, height:60, borderRadius:'50%', objectFit:'cover', border:'2px solid #E4E6EB' }}/>\n                  <div>\n                    <p style={{ fontWeight:600, fontSize:13, color:'#050505' }}>{f.fullName}{f.isVip&&<img src='/vip-badge.png' style={{ width:32, height:32, marginLeft:5, verticalAlign:'middle', display:'inline-block', flexShrink:0, objectFit:'contain' }} alt='VIP'/>}</p>\n                    <p style={{ fontSize:11, color:'#65676B' }}>@{f.username}</p>\n                  </div>\n                  <button onClick={e=>{e.stopPropagation();navigate(`/messages/${getChatId(currentUser.uid,f.uid)}`);}} style={{ background:'#E4E6EB', border:'none', borderRadius:16, padding:'5px 12px', color:'#1877F2', cursor:'pointer', fontSize:12, display:'flex', alignItems:'center', gap:4 }}><HiPaperAirplane size={12}/>Message</button>\n                </div>\n              ))}\n            </div>\n        )}\n\n        {(activeTab==='posts'||activeTab==='sales')&&(\n          getTabContent().length===0\n            ? <div style={{ textAlign:'center', padding:40, color:'#65676B' }}>Aucun contenu</div>\n            : (<>\n                {getTabContent().slice(0, visibleCount).map(post => renderPost(post))}\n                {getTabContent().length > visibleCount && (\n                  <div ref={el => { if (!el) return; const io = new IntersectionObserver(es => { if (es[0].isIntersecting) setVisibleCount(c => c + 10); }, { rootMargin: '400px' }); io.observe(el); }}\n                    style={{ padding: 18, textAlign: 'center', color: '#65676B', fontSize: 13 }}>Chargement\u2026</div>\n                )}\n              </>)\n        )}\n      </div>\n\n      {/* \u2500\u2500 Modal : Archive de votre story \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */}\n      {storyArchive !== null && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.55)', zIndex:400, display:'flex', alignItems:'flex-end', justifyContent:'center' }} onClick={() => setStoryArchive(null)}>\n          <div onClick={e => e.stopPropagation()} style={{ background:'white', borderRadius:'20px 20px 0 0', padding:18, width:'100%', maxWidth:520, maxHeight:'85vh', overflowY:'auto' }}>\n            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:12 }}>\n              <h3 style={{ fontWeight:800, color:'#1877F2' }}>\ud83d\uddc2\ufe0f Archive</h3>\n              <button onClick={() => setStoryArchive(null)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={20}/></button>\n            </div>\n            {storyArchive.length === 0 && <p style={{ fontSize:14, color:'#65676B', textAlign:'center', padding:'20px 0' }}>Aucune story dans l'archive.</p>}\n            <div style={{ display:'grid', gridTemplateColumns:'repeat(3, 1fr)', gap:8 }}>\n              {storyArchive.map(st => (\n                <div key={st.id} style={{ position:'relative', borderRadius:12, overflow:'hidden', aspectRatio:'9/16', background:'#000' }}>\n                  {st.mediaType === 'video'\n                    ? <video src={st.mediaURL} muted playsInline preload=\"metadata\" style={{ width:'100%', height:'100%', objectFit:'cover' }}/>\n                    : <img src={st.mediaURL} alt=\"\" style={{ width:'100%', height:'100%', objectFit:'cover' }}/>}\n                  <span style={{ position:'absolute', bottom:4, left:6, color:'white', fontSize:10, fontWeight:600, textShadow:'0 1px 4px rgba(0,0,0,.8)' }}>\n                    {st.ts ? new Date(st.ts).toLocaleDateString('fr-FR') : ''}\n                  </span>\n                  <button onClick={() => deleteArchivedStory(st)}\n                    style={{ position:'absolute', top:4, right:4, width:24, height:24, borderRadius:'50%', background:'rgba(0,0,0,.55)', border:'none', cursor:'pointer', color:'white', display:'flex', alignItems:'center', justifyContent:'center' }}>\n                    <HiTrash size={12}/>\n                  </button>\n                </div>\n              ))}\n            </div>\n          </div>\n        </div>\n      )}\n\n      {/* \u2500\u2500 Modal : Souvenirs \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */}\n      {souvenirs !== null && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.55)', zIndex:400, display:'flex', alignItems:'flex-end', justifyContent:'center' }} onClick={() => setSouvenirs(null)}>\n          <div onClick={e => e.stopPropagation()} style={{ background:'white', borderRadius:'20px 20px 0 0', padding:18, width:'100%', maxWidth:520, maxHeight:'85vh', overflowY:'auto' }}>\n            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:12 }}>\n              <h3 style={{ fontWeight:800, color:'#1877F2' }}>\ud83d\udd70\ufe0f Souvenirs</h3>\n              <button onClick={() => setSouvenirs(null)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={20}/></button>\n            </div>\n            {souvenirs.length === 0 && (\n              <p style={{ fontSize:14, color:'#65676B', textAlign:'center', padding:'20px 0' }}>\n                Aucun souvenir aujourd'hui.<br/>\n                <span style={{ fontSize:12 }}>Les publications faites le m\u00eame jour les ann\u00e9es pass\u00e9es appara\u00eetront ici.</span>\n              </p>\n            )}\n            {souvenirs.map(sp => (\n              <div key={sp.id} onClick={() => { setSouvenirs(null); navigate(`/post/${sp.id}`); }}\n                style={{ display:'flex', alignItems:'center', gap:12, padding:'10px 4px', cursor:'pointer', borderBottom:'1px solid #F0F2F5' }}>\n                {sp.mediaURL\n                  ? (sp.mediaType === 'video'\n                      ? <video src={sp.mediaURL} muted playsInline preload=\"metadata\" style={{ width:56, height:56, borderRadius:10, objectFit:'cover', flexShrink:0, background:'#000' }}/>\n                      : <img src={sp.mediaURL} alt=\"\" style={{ width:56, height:56, borderRadius:10, objectFit:'cover', flexShrink:0 }}/>)\n                  : <div style={{ width:56, height:56, borderRadius:10, background:'#E7F0FE', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0, fontSize:22 }}>\ud83d\udcdd</div>}\n                <div style={{ flex:1, minWidth:0 }}>\n                  <p style={{ fontSize:13, color:'#050505', overflow:'hidden', textOverflow:'ellipsis', display:'-webkit-box', WebkitLineClamp:2, WebkitBoxOrient:'vertical' }}>\n                    {sp.content || (sp.mediaType === 'video' ? '\ud83c\udfac Vid\u00e9o' : '\ud83d\udcf7 Photo')}\n                  </p>\n                  <p style={{ fontSize:11, color:'#1877F2', fontWeight:700, marginTop:2 }}>\n                    Il y a {new Date().getFullYear() - sp.createdAt.toDate().getFullYear()} an(s) \u2014 {sp.createdAt.toDate().toLocaleDateString('fr-FR')}\n                  </p>\n                </div>\n              </div>\n            ))}\n          </div>\n        </div>\n      )}\n\n      {shareModalPost && <ShareModal post={shareModalPost} onClose={() => setShareModalPost(null)} />}\n      {followListOpen && (\n        <FollowListModal\n          uids={followListOpen === 'followers' ? (profile.followers||[]) : (profile.following||[])}\n          title={followListOpen === 'followers' ? 'Abonn\u00e9s' : 'Suivi(e)s'}\n          onClose={() => setFollowListOpen(null)}\n        />\n      )}\n      {boostTarget && (\n        <BoostOrderModal target={boostTarget} onClose={() => setBoostTarget(null)} />\n      )}\n      {reportOpen && (\n        <ReportModal title=\"Signaler le profil\" onConfirm={submitReportUser} onClose={() => setReportOpen(false)} />\n      )}\n    </div>\n    </>\n  );\n}";
const GROUP_SRC="// src/pages/GroupPage.jsx \u2014 Page d'un groupe public (format Facebook)\nimport { useState, useEffect, useRef } from 'react';\nimport { useParams, useNavigate } from 'react-router-dom';\nimport {\n  doc, onSnapshot, updateDoc, deleteDoc, collection, query, where,\n  addDoc, serverTimestamp, arrayUnion, arrayRemove, getDoc, writeBatch\n} from 'firebase/firestore';\nimport { db } from '../firebase';\nimport { NeonPlaneWhite } from '../components/NeonIcons';\nimport MusicPostCard from '../components/MusicPostCard';\nimport { useAuth } from '../context/AuthContext';\nimport { timeAgo } from '../utils/timeAgo';\nimport { uploadToTelegram } from '../utils/telegram';\nimport { captureVideoThumb } from '../utils/videoThumb';\nimport { startBackgroundUpload } from '../utils/uploadManager';\nimport { isDataSaverOn, subscribeDataSaver } from '../utils/dataSaver';\nimport { downloadMedia } from '../utils/download';\nimport ShareModal from '../components/ShareModal';\nimport { SkeletonChannelPage } from '../components/Skeleton';\nimport MediaViewer from '../components/MediaViewer';\nimport {\n  HiUserGroup, HiCamera, HiArrowLeft, HiPlus, HiCheck, HiTrash,\n  HiPhotograph, HiVideoCamera, HiChat, HiShare, HiX, HiUserAdd, HiDotsVertical,\n  HiDownload, HiSearch, HiShoppingBag, HiShoppingCart, HiPhone, HiLocationMarker, HiOutlineChat\n} from 'react-icons/hi';\nimport { addToCart } from '../utils/cart';\n\nconst REACTIONS = ['\u2764\ufe0f','\ud83d\ude02','\ud83d\ude2e','\ud83d\ude22','\ud83d\ude21','\ud83d\udc4d'];\n\nexport default function GroupPage() {\n  const { groupId } = useParams();\n  const { currentUser, userProfile } = useAuth();\n  const navigate = useNavigate();\n\n  const [group,      setGroup]      = useState(null);\n  const [notFound,   setNotFound]   = useState(false);\n  const [members,    setMembers]    = useState([]);\n  const [posts,      setPosts]      = useState([]);\n  const [visibleCount, setVisibleCount] = useState(10);\n  const [content,    setContent]    = useState('');\n  const [textBg,     setTextBg]     = useState(null);\n  const [mediaFile,  setMediaFile]  = useState(null);\n  const [mediaPreview, setMediaPreview] = useState(null);\n  const [mediaType,  setMediaType]  = useState('');\n  const [posting,    setPosting]    = useState(false);\n  const [gpLocation, setGpLocation] = useState('');\n  const [gpMood,     setGpMood]     = useState('');\n  const [gpAllowMessages, setGpAllowMessages] = useState(true);\n  const [gpMoreOpen, setGpMoreOpen] = useState(false);\n  const [gpFullOpen, setGpFullOpen] = useState(false);\n  const [gpLocationOpen, setGpLocationOpen] = useState(false);\n  const [gpMoodOpen, setGpMoodOpen] = useState(false);\n  const [gpTagOpen,  setGpTagOpen]  = useState(false);\n  const [gpTagSel,   setGpTagSel]   = useState({});\n  const [gpTagList,  setGpTagList]  = useState([]);\n  const MOODS = ['\ud83d\ude0a se sent heureux(se)', '\ud83d\ude22 se sent triste', '\ud83e\udd73 fait la f\u00eate', '\ud83d\ude34 fatigu\u00e9(e)', '\ud83d\ude4f reconnaissant(e)', '\ud83d\udcaa motiv\u00e9(e)', '\ud83d\ude0d amoureux(se)', '\ud83e\udd12 malade'];\n  const [uploadingCover, setUploadingCover] = useState(false);\n  const [uploadingPhoto, setUploadingPhoto] = useState(false);\n  const [showReact,  setShowReact]  = useState({});\n  const [postMenu,   setPostMenu]   = useState(null);\n  const [dataSaver,  setDataSaverState] = useState(isDataSaverOn());\n  useEffect(() => subscribeDataSaver(setDataSaverState), []);\n  const [shareModalPost, setShareModalPost] = useState(null);\n  const [viewerState,    setViewerState]    = useState(null); // { post, index }\n  const [addMemberOpen, setAddMemberOpen] = useState(false);\n  const [friendsList, setFriendsList] = useState([]);\n  const [memberSearch, setMemberSearch] = useState('');\n  const [menuOpen,   setMenuOpen]   = useState(false);\n\n  // Modifier le groupe (admin uniquement)\n  const [editOpen,   setEditOpen]   = useState(false);\n  const [editName,   setEditName]   = useState('');\n  const [editDesc,   setEditDesc]   = useState('');\n  const [savingEdit, setSavingEdit] = useState(false);\n  const [allMembers, setAllMembers] = useState([]);\n\n  const coverRef = useRef(); const photoRef = useRef();\n  const postPhotoRef = useRef(); const postVideoRef = useRef();\n\n  const isMember = !!group?.members?.includes(currentUser?.uid);\n  const isAdmin  = !!group?.admins?.includes(currentUser?.uid);\n\n  // Groupe en temps r\u00e9el\n  useEffect(() => {\n    const unsub = onSnapshot(doc(db, 'groups', groupId), snap => {\n      if (!snap.exists()) { setNotFound(true); return; }\n      setGroup({ id: snap.id, ...snap.data() });\n    }, err => console.error('Lecture groupe refus\u00e9e:', err?.message || err));\n    return () => unsub();\n  }, [groupId]);\n\n  // Profils des premiers membres (avatars)\n  useEffect(() => {\n    if (!group?.members?.length) { setMembers([]); return; }\n    Promise.all(group.members.slice(0, 8).map(uid =>\n      getDoc(doc(db, 'users', uid)).then(s => s.exists() ? { uid, ...s.data() } : null).catch(() => null)\n    )).then(list => setMembers(list.filter(Boolean)));\n  }, [group?.members?.join?.(',')]);\n\n  // Publications du groupe (tri c\u00f4t\u00e9 client \u2014 pas d'index composite requis)\n  useEffect(() => {\n    const q = query(collection(db, 'posts'), where('groupId', '==', groupId));\n    const unsub = onSnapshot(q, snap => {\n      const list = snap.docs.map(d => ({ id: d.id, ...d.data() }));\n      list.sort((a, b) => (b.createdAt?.seconds || 0) - (a.createdAt?.seconds || 0));\n      setPosts(list);\n    }, err => console.error('Lecture posts groupe:', err?.message || err));\n    return () => unsub();\n  }, [groupId]);\n\n  // Fermer le menu au clic ext\u00e9rieur\n  useEffect(() => {\n    const fn = () => { setMenuOpen(false); setPostMenu(null); };\n    document.addEventListener('click', fn);\n    return () => document.removeEventListener('click', fn);\n  }, []);\n\n  async function changeImage(e, field) {\n    const file = e.target.files[0]; if (!file) return;\n    const setter = field === 'coverURL' ? setUploadingCover : setUploadingPhoto;\n    setter(true);\n    try {\n      const r = await uploadToTelegram(file);\n      await updateDoc(doc(db, 'groups', groupId), { [field]: r.url });\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n    setter(false);\n    e.target.value = '';\n  }\n\n  async function joinGroup() {\n    try { await updateDoc(doc(db, 'groups', groupId), { members: arrayUnion(currentUser.uid) }); }\n    catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  async function leaveGroup() {\n    if (!window.confirm(`Quitter le groupe \"${group.name}\" ?`)) return;\n    await updateDoc(doc(db, 'groups', groupId), {\n      members: arrayRemove(currentUser.uid),\n      admins: arrayRemove(currentUser.uid),\n    });\n  }\n\n  async function deleteGroup() {\n    if (!isAdmin) return;\n    if (!window.confirm(`Supprimer d\u00e9finitivement \"${group.name}\" ?`)) return;\n    await deleteDoc(doc(db, 'groups', groupId));\n    navigate('/groups');\n  }\n\n  async function openEdit() {\n    setEditName(group.name || '');\n    setEditDesc(group.description || '');\n    setEditOpen(true);\n    const list = await Promise.all((group.members || []).slice(0, 60).map(uid =>\n      getDoc(doc(db, 'users', uid)).then(sn => sn.exists() ? { uid, ...sn.data() } : null).catch(() => null)\n    ));\n    setAllMembers(list.filter(Boolean));\n  }\n\n  async function saveEdit() {\n    const n = editName.trim();\n    if (!n) { alert('Le nom ne peut pas \u00eatre vide'); return; }\n    setSavingEdit(true);\n    try {\n      await updateDoc(doc(db, 'groups', groupId), { name: n, description: editDesc.trim().slice(0, 300) });\n      setEditOpen(false);\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n    setSavingEdit(false);\n  }\n\n  async function toggleAdmin(uid) {\n    const isA = group.admins?.includes(uid);\n    if (isA && group.admins.length === 1) { alert('Le groupe doit garder au moins un admin.'); return; }\n    try {\n      await updateDoc(doc(db, 'groups', groupId), { admins: isA ? arrayRemove(uid) : arrayUnion(uid) });\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n  }\n\n  function copyInviteLink() {\n    const url = `${window.location.origin}/groups/${groupId}`;\n    if (navigator.share) { navigator.share({ title: group.name, text: `Rejoignez le groupe ${group.name} sur Trengo !`, url }).catch(() => {}); }\n    else { navigator.clipboard?.writeText(url); alert('Lien du groupe copi\u00e9 !'); }\n  }\n\n  const [selectedFriends, setSelectedFriends] = useState({});\n  const [addingMembers, setAddingMembers] = useState(false);\n\n  async function openAddMember() {\n    setAddMemberOpen(true); setMemberSearch(''); setSelectedFriends({});\n    const myFriends = userProfile?.friends || [];\n    const notIn = myFriends.filter(uid => !group.members?.includes(uid));\n    const list = await Promise.all(notIn.map(uid =>\n      getDoc(doc(db, 'users', uid)).then(sn => sn.exists() ? { uid, ...sn.data() } : null).catch(() => null)\n    ));\n    setFriendsList(list.filter(Boolean));\n  }\n\n  async function addSelectedMembers() {\n    const uids = Object.keys(selectedFriends).filter(k => selectedFriends[k]);\n    if (uids.length === 0) return;\n    setAddingMembers(true);\n    try {\n      await updateDoc(doc(db, 'groups', groupId), { members: arrayUnion(...uids) });\n      const batch = writeBatch(db);\n      uids.forEach(uid => batch.set(doc(collection(db, 'notifications')), {\n        toUid: uid, fromUid: currentUser.uid,\n        fromName: userProfile.fullName, fromPhoto: userProfile.photoURL || '',\n        type: 'general', message: `${userProfile.fullName} vous a ajout\u00e9(e) au groupe ${group.name}`,\n        read: false, createdAt: serverTimestamp(),\n      }));\n      await batch.commit();\n      setAddMemberOpen(false);\n    } catch (err) { alert('Erreur : ' + (err?.message || err)); }\n    setAddingMembers(false);\n  }\n\n  function handleMedia(e, type) {\n    const file = e.target.files[0]; if (!file) return;\n    setTextBg(null); setMediaFile(file); setMediaType(type); setMediaPreview(URL.createObjectURL(file));\n  }\n\n  // Publie dans le groupe (caption captur\u00e9e en param\u00e8tre \u2014 utilisable aussi\n  // depuis le callback d'upload en arri\u00e8re-plan)\n  async function finalizePublish(caption, mediaURL, finalMT, thumbURL) {\n    const postRef = await addDoc(collection(db, 'posts'), {\n      uid: currentUser.uid, authorName: userProfile.fullName,\n      authorUsername: userProfile.username, authorPhoto: userProfile.photoURL || '',\n      authorIsVip: userProfile.isVip || false,\n      content: (caption || '').trim().slice(0, 2000), mediaURL, mediaType: finalMT, thumbURL: thumbURL || '',\n      isSale: false, price: '', contact: '', lieu: '',\n      location: gpLocation.trim(), mood: gpMood, allowMessages: gpAllowMessages,\n      taggedUids: Object.keys(gpTagSel).filter(k => gpTagSel[k]),\n      taggedNames: gpTagList.filter(f => gpTagSel[f.uid]).map(f => f.fullName),\n      groupId: group.id, groupName: group.name, groupPhoto: group.photoURL || '',\n      textBg: textBg || null,\n      reactions: {}, comments: [], createdAt: serverTimestamp(),\n    });\n    try {\n      const targets = (group.members || []).filter(m => m !== currentUser.uid);\n      if (targets.length > 0) {\n        const batch = writeBatch(db);\n        targets.forEach(fUid => batch.set(doc(collection(db, 'notifications')), {\n          toUid: fUid, fromUid: currentUser.uid,\n          fromName: userProfile.fullName, fromPhoto: userProfile.photoURL || '',\n          type: 'post', postId: postRef.id,\n          message: `${userProfile.fullName} a publi\u00e9 dans le groupe ${group.name}`,\n          read: false, createdAt: serverTimestamp(),\n        }));\n        await batch.commit();\n      }\n    } catch (notifErr) { console.warn('Notification \u00e9chou\u00e9e (publication d\u00e9j\u00e0 faite) :', notifErr?.message || notifErr); }\n    setGpLocation(''); setGpMood(''); setGpAllowMessages(true); setGpTagSel({});\n  }\n\n  async function openGpTagModal() {\n    setGpTagOpen(true);\n    const myFriends = userProfile?.friends || [];\n    const list = await Promise.all(myFriends.map(uid =>\n      getDoc(doc(db, 'users', uid)).then(sn => sn.exists() ? { uid, ...sn.data() } : null).catch(() => null)\n    ));\n    setGpTagList(list.filter(Boolean));\n  }\n\n  async function publishInGroup() {\n    if (!content.trim() && !mediaFile) return;\n\n    // Miniature (poster) \u2014 alaina alohan'ny upload\n    let thumbFile = null;\n    if (mediaFile && mediaFile.type.startsWith('video/')) {\n      try { thumbFile = await captureVideoThumb(mediaFile); } catch {}\n    }\n\n    // Vid\u00e9o > 12 Mo : upload ARRI\u00c8RE-PLAN (afaka mifindra page)\n    if (mediaFile && mediaFile.type.startsWith('video/') && mediaFile.size > 12 * 1024 * 1024) {\n      const cText = content;\n      const started = startBackgroundUpload(mediaFile, 'Vid\u00e9o', async r => {\n        let thumbURL = '';\n        if (thumbFile) { try { const tr = await uploadToTelegram(thumbFile); thumbURL = tr.url || ''; } catch {} }\n        await finalizePublish(cText, r.url, 'video', thumbURL);\n      });\n      if (started) { setContent(''); setMediaFile(null); setMediaPreview(null); setMediaType(''); }\n      return;\n    }\n\n    setPosting(true);\n    try {\n      let mediaURL = '', finalMT = mediaType, thumbURL = '';\n      if (mediaFile) {\n        const r = await uploadToTelegram(mediaFile);\n        mediaURL = r.url; finalMT = r.type === 'video' ? 'video' : 'image';\n        if (thumbFile) { try { const tr = await uploadToTelegram(thumbFile); thumbURL = tr.url || ''; } catch {} }\n      }\n      await finalizePublish(content, mediaURL, finalMT, thumbURL);\n      setTextBg(null); setContent(''); setMediaFile(null); setMediaPreview(null); setMediaType(''); setGpFullOpen(false); setGpLocation(''); setGpMood(''); setGpTagSel({});\n    } catch (err) { alert('Erreur lors de la publication : ' + (err?.message || err)); }\n    setPosting(false);\n  }\n\n  async function reactToPost(postId, emoji) {\n    if (!REACTIONS.includes(emoji)) return;\n    const post = posts.find(p => p.id === postId); if (!post) return;\n    const reactions = post.reactions || {};\n    const my = reactions[currentUser.uid];\n    if (my === emoji) {\n      const u = { ...reactions }; delete u[currentUser.uid];\n      await updateDoc(doc(db, 'posts', postId), { reactions: u });\n    } else {\n      await updateDoc(doc(db, 'posts', postId), { [`reactions.${currentUser.uid}`]: emoji });\n    }\n    setShowReact(p => ({ ...p, [postId]: false }));\n  }\n\n  function sharePost(post) {\n    setShareModalPost(post);\n  }\n\n  async function deletePostInGroup(post) {\n    if (!window.confirm('Supprimer cette publication ?')) return;\n    try { await deleteDoc(doc(db, 'posts', post.id)); }\n    catch (err) { alert('Erreur : ' + (err?.message || err)); }\n    setPostMenu(null);\n  }\n\n  if (notFound) return (\n    <div style={{ padding: 40, textAlign: 'center' }}>\n      <p style={{ fontWeight: 700, marginBottom: 10 }}>Ce groupe n'existe plus.</p>\n      <button className=\"btn-blue\" onClick={() => navigate('/groups')} style={{ padding: '10px 20px', borderRadius: 20 }}>Voir les groupes</button>\n    </div>\n  );\n  if (!group) return <SkeletonChannelPage />;\n\n  const av = u => u.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(u.fullName || 'U')}&background=1877F2&color=fff`;\n\n  return (\n    <div style={{ paddingBottom: 20 }}>\n\n      {/* \u2500\u2500 Photo de couverture \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */}\n      <div style={{ position: 'relative', height: 180, background: group.coverURL ? '#000' : 'linear-gradient(135deg,#1877F2,#FF2D8D,#F2B300)' }}>\n        {group.coverURL && <img src={group.coverURL} alt=\"\" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />}\n        <button onClick={() => navigate('/groups')}\n          style={{ position: 'absolute', top: 10, left: 10, width: 36, height: 36, borderRadius: '50%', background: 'rgba(0,0,0,.45)', border: 'none', cursor: 'pointer', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>\n          <HiArrowLeft size={20} />\n        </button>\n        {isAdmin && (\n          <>\n            <input ref={coverRef} type=\"file\" accept=\"image/*\" style={{ display: 'none' }} onChange={e => changeImage(e, 'coverURL')} />\n            <button onClick={() => coverRef.current?.click()} disabled={uploadingCover}\n              style={{ position: 'absolute', bottom: 10, right: 10, background: 'rgba(255,255,255,.92)', border: 'none', borderRadius: 18, padding: '7px 12px', cursor: 'pointer', fontSize: 12, fontWeight: 700, color: '#050505', display: 'flex', alignItems: 'center', gap: 5, fontFamily: 'Poppins' }}>\n              <HiCamera size={15} /> {uploadingCover ? 'Envoi...' : 'Couverture'}\n            </button>\n          </>\n        )}\n        {/* Photo du groupe */}\n        <div style={{ position: 'absolute', bottom: -34, left: 16 }}>\n          <div style={{ position: 'relative' }}>\n            <div style={{ width: 78, height: 78, borderRadius: 18, background: 'linear-gradient(135deg,#1B84FF,#1877F2)', border: '4px solid white', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 4px 14px rgba(0,0,0,.2)', overflow: 'hidden' }}>\n              {group.photoURL\n                ? <img src={group.photoURL} alt=\"\" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />\n                : <HiUserGroup size={34} color=\"white\" />}\n            </div>\n            {isAdmin && (\n              <>\n                <input ref={photoRef} type=\"file\" accept=\"image/*\" style={{ display: 'none' }} onChange={e => changeImage(e, 'photoURL')} />\n                <button onClick={() => photoRef.current?.click()} disabled={uploadingPhoto}\n                  style={{ position: 'absolute', bottom: -4, right: -4, width: 28, height: 28, borderRadius: '50%', background: '#1877F2', border: '2.5px solid white', cursor: 'pointer', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>\n                  <HiCamera size={13} />\n                </button>\n              </>\n            )}\n          </div>\n        </div>\n      </div>\n\n      {/* \u2500\u2500 Infos du groupe \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */}\n      <div style={{ padding: '42px 16px 0' }}>\n        <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between' }}>\n          <div style={{ minWidth: 0 }}>\n            <h2 style={{ fontWeight: 800, fontSize: 20 }}>\n              {group.name}\n              {isAdmin && <span style={{ marginLeft: 6, fontSize: 10, fontWeight: 700, color: '#F2B300', background: '#FFF6DB', borderRadius: 8, padding: '2px 7px', verticalAlign: 'middle' }}>ADMIN</span>}\n            </h2>\n            <p style={{ fontSize: 13, color: '#65676B', marginTop: 2 }}>\n              \ud83c\udf0d Groupe public \u00b7 {group.members?.length || 0} membre{(group.members?.length || 0) > 1 ? 's' : ''}\n            </p>\n          </div>\n          <div style={{ position: 'relative', flexShrink: 0 }} onClick={e => e.stopPropagation()}>\n            <button onClick={() => setMenuOpen(p => !p)} style={{ background: '#F0F2F5', border: 'none', borderRadius: '50%', width: 34, height: 34, cursor: 'pointer', color: '#050505', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>\n              <HiDotsVertical size={17} />\n            </button>\n            {menuOpen && (\n              <div style={{ position: 'absolute', top: '100%', right: 0, background: 'white', border: '1px solid #E4E6EB', borderRadius: 12, boxShadow: '0 4px 20px rgba(0,0,0,.14)', minWidth: 190, zIndex: 50, overflow: 'hidden' }}>\n                {isAdmin && <button onClick={() => { setMenuOpen(false); openEdit(); }} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '12px 16px', background: 'none', border: 'none', cursor: 'pointer', fontFamily: 'Poppins', fontSize: 14, color: '#1877F2', borderBottom: '1px solid #F0F2F5' }}><HiCamera size={16} /> Modifier le groupe</button>}\n                {isMember && <button onClick={() => { setMenuOpen(false); leaveGroup(); }} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '12px 16px', background: 'none', border: 'none', cursor: 'pointer', fontFamily: 'Poppins', fontSize: 14, color: '#F2B300', borderBottom: '1px solid #F0F2F5' }}><HiArrowLeft size={16} /> Quitter le groupe</button>}\n                {isAdmin && <button onClick={() => { setMenuOpen(false); deleteGroup(); }} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '12px 16px', background: 'none', border: 'none', cursor: 'pointer', fontFamily: 'Poppins', fontSize: 14, color: '#FF2D8D' }}><HiTrash size={16} /> Supprimer le groupe</button>}\n              </div>\n            )}\n          </div>\n        </div>\n\n        {group.description && <p style={{ fontSize: 14, marginTop: 8, color: '#050505' }}>{group.description}</p>}\n\n        {/* Avatars membres + Inviter / Rejoindre */}\n        <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginTop: 12 }}>\n          <div style={{ display: 'flex' }}>\n            {members.map((m, i) => (\n              <img key={m.uid} src={av(m)} alt=\"\" onClick={() => navigate(`/profile/${m.uid}`)}\n                style={{ width: 34, height: 34, borderRadius: '50%', objectFit: 'cover', border: '2.5px solid white', marginLeft: i ? -10 : 0, cursor: 'pointer' }} />\n            ))}\n          </div>\n          {isMember\n            ? <button onClick={openAddMember} className=\"btn-blue\" style={{ flex: 1, padding: '10px 0', fontSize: 14, borderRadius: 10, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6 }}>\n                <HiUserAdd size={16} /> Ajouter un membre\n              </button>\n            : <button onClick={joinGroup} className=\"btn-blue\" style={{ flex: 1, padding: '10px 0', fontSize: 14, borderRadius: 10, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6 }}>\n                <HiPlus size={16} /> Rejoindre le groupe\n              </button>}\n        </div>\n      </div>\n\n      {/* \u2500\u2500 Composer groupe : barre kely (ic\u00f4ne fotsiny) \u2500\u2500\u2500\u2500\u2500\u2500 */}\n      {isMember && (\n        <div className=\"card post-card\" style={{ padding: 12, marginTop: 14, marginBottom: 8 }}>\n          <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>\n            <img src={userProfile?.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(userProfile?.fullName || 'U')}&background=1877F2&color=fff`}\n              alt=\"\" className=\"avatar\" style={{ width: 40, height: 40, flexShrink: 0 }} />\n            <button onClick={() => setGpFullOpen(true)}\n              style={{ flex:1, textAlign:'left', background:'#F0F2F5', border:'none', borderRadius:22, padding:'10px 16px', color:'#65676B', fontSize:14.5, fontFamily:'Poppins', cursor:'pointer' }}>\n              Exprimez-vous dans le groupe...\n            </button>\n          </div>\n          <div style={{ display:'flex', alignItems:'center', marginTop:10, paddingTop:8, borderTop:'1px solid #E4E6EB' }}>\n            <button onClick={() => { setGpFullOpen(true); setTimeout(() => postPhotoRef.current?.click(), 60); }} title=\"Photo\"\n              style={{ flex:1, display:'flex', justifyContent:'center', alignItems:'center', background:'none', border:'none', cursor:'pointer', padding:'6px 0' }}>\n              <HiPhotograph size={22} color=\"#45BD62\" />\n            </button>\n            <button onClick={() => { setGpFullOpen(true); setTimeout(() => postVideoRef.current?.click(), 60); }} title=\"Vid\u00e9o\"\n              style={{ flex:1, display:'flex', justifyContent:'center', alignItems:'center', background:'none', border:'none', cursor:'pointer', padding:'6px 0', borderLeft:'1px solid #E4E6EB' }}>\n              <HiVideoCamera size={22} color=\"#F3425F\" />\n            </button>\n            <button onClick={() => setGpFullOpen(true)} title=\"Plus\"\n              style={{ flex:1, display:'flex', justifyContent:'center', alignItems:'center', gap:5, background:'none', border:'none', cursor:'pointer', padding:'6px 0', borderLeft:'1px solid #E4E6EB', color:'#1877F2', fontWeight:700, fontSize:13, fontFamily:'Poppins' }}>\n              <span style={{ fontSize:18 }}>\uff0b</span> Publi\u00e9\n            </button>\n          </div>\n        </div>\n      )}\n\n      {/* \u2500\u2500 PAGE FENO : Publier dans le groupe (tsy misy vente/\u00e9v\u00e9nement/direct) \u2500\u2500 */}\n      {gpFullOpen && (\n      <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.35)', zIndex:350, display:'flex', alignItems:'flex-start', justifyContent:'center', overflowY:'auto' }}>\n      <div className=\"card post-card\" style={{ padding:16, width:'100%', maxWidth:600, minHeight:'100vh', borderRadius:0 }}>\n        <div style={{ display:'flex', alignItems:'center', gap:12, marginBottom:14, paddingBottom:12, borderBottom:'1px solid #E4E6EB' }}>\n          <button onClick={() => setGpFullOpen(false)} style={{ background:'none', border:'none', cursor:'pointer', padding:4 }}><HiX size={24} color=\"#050505\"/></button>\n          <h3 style={{ fontWeight:800, fontSize:18, flex:1 }}>Publier dans le groupe</h3>\n          <button className=\"btn-gold\" onClick={() => publishInGroup()} disabled={posting || (!content.trim() && !mediaFile)} style={{ padding:'7px 20px', fontSize:14 }}>\n            {posting ? '...' : 'Publier'}\n          </button>\n        </div>\n        <div style={{ display:'flex', gap:10, alignItems:'flex-start' }}>\n          <img src={userProfile?.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(userProfile?.fullName || 'U')}&background=1877F2&color=fff`} alt=\"\" className=\"avatar\" style={{ width:42, height:42, flexShrink:0 }}/>\n          {textBg ? (\n            <div style={{ flex:1, background:textBg, borderRadius:14, minHeight:160, display:'flex', alignItems:'center', justifyContent:'center', padding:'18px 14px' }}>\n              <textarea placeholder=\"\u00c9crire quelque chose...\" value={content} onChange={e => setContent(e.target.value)} style={{ resize:'none', width:'100%', border:'none', background:'transparent', color:'#fff', fontWeight:800, fontSize:22, textAlign:'center', outline:'none', lineHeight:1.4, minHeight:80 }} maxLength={2000} autoFocus/>\n            </div>\n          ) : (\n            <textarea className=\"input\" placeholder=\"Exprimez-vous...\" value={content} onChange={e => setContent(e.target.value)} rows={3} style={{ resize:'none', flex:1, border:'none', fontSize:17 }} maxLength={2000} autoFocus/>\n          )}\n        </div>\n          {!mediaPreview && (\n          <div style={{ display:'flex', gap:8, marginTop:10, alignItems:'center', justifyContent:'center', flexWrap:'wrap' }}>\n            {[null,'linear-gradient(135deg,#1877F2,#42A5F5)','linear-gradient(135deg,#E91E8C,#FF6BB5)','linear-gradient(135deg,#FF7A00,#FFB347)','linear-gradient(135deg,#00C853,#69F0AE)','linear-gradient(135deg,#7C3AED,#A78BFA)'].map((bg,i)=>(\n              <button key={i} onClick={()=>setTextBg(bg)} style={{ width:textBg===bg?32:28, height:textBg===bg?32:28, borderRadius:'50%', padding:0, cursor:'pointer', flexShrink:0, background:bg||'#ffffff', border:textBg===bg?'3px solid #050505':'2px solid #E4E6EB', transition:'all .15s' }}/>\n            ))}\n          </div>\n          )}\n          {(gpLocation || gpMood || Object.values(gpTagSel).some(Boolean)) && (\n            <div style={{ display:'flex', flexWrap:'wrap', gap:6, marginTop:8 }}>\n              {gpLocation && <span style={{ display:'flex', alignItems:'center', gap:5, background:'#FFE9F2', color:'#FF2D8D', borderRadius:16, padding:'4px 10px', fontSize:12, fontWeight:700 }}>\ud83d\udccd {gpLocation} <span onClick={() => setGpLocation('')} style={{ cursor:'pointer' }}>\u2715</span></span>}\n              {gpMood && <span style={{ display:'flex', alignItems:'center', gap:5, background:'#FFF6DB', color:'#B8860B', borderRadius:16, padding:'4px 10px', fontSize:12, fontWeight:700 }}>{gpMood} <span onClick={() => setGpMood('')} style={{ cursor:'pointer' }}>\u2715</span></span>}\n              {Object.values(gpTagSel).some(Boolean) && <span style={{ display:'flex', alignItems:'center', gap:5, background:'#E7F0FE', color:'#1877F2', borderRadius:16, padding:'4px 10px', fontSize:12, fontWeight:700 }}>\ud83c\udff7\ufe0f avec {gpTagList.filter(f => gpTagSel[f.uid]).map(f => f.fullName).join(', ')} <span onClick={() => setGpTagSel({})} style={{ cursor:'pointer' }}>\u2715</span></span>}\n            </div>\n          )}\n          {mediaPreview && (\n            <div style={{ position: 'relative', marginTop: 10 }}>\n              {mediaType === 'image'\n                ? <img src={mediaPreview} alt=\"\" style={{ width: '100%', borderRadius: 10, maxHeight: 240, objectFit: 'cover' }} />\n                : <video src={mediaPreview} controls style={{ width: '100%', borderRadius: 10, maxHeight: 240 }} />}\n              <button onClick={() => { setMediaFile(null); setMediaPreview(null); setMediaType(''); }}\n                style={{ position: 'absolute', top: 6, right: 6, background: 'rgba(0,0,0,.55)', border: 'none', borderRadius: '50%', width: 28, height: 28, cursor: 'pointer', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><HiX size={15} /></button>\n            </div>\n          )}\n          {/* Options \u2014 tsy misy Vente / \u00c9v\u00e9nement / En direct (groupe) */}\n          <div style={{ marginTop:16, border:'1px solid #E4E6EB', borderRadius:12, overflow:'hidden' }}>\n            <input ref={postPhotoRef} type=\"file\" accept=\"image/*\" style={{ display: 'none' }} onChange={e => handleMedia(e, 'image')} />\n            <input ref={postVideoRef} type=\"file\" accept=\"video/mp4,video/webm,video/quicktime\" style={{ display: 'none' }} onChange={e => handleMedia(e, 'video')} />\n            {[\n              { icon:<HiPhotograph size={22} color=\"#45BD62\"/>, label:'Photo / Vid\u00e9o', action:() => postPhotoRef.current?.click() },\n              { icon:<HiVideoCamera size={22} color=\"#F3425F\"/>, label:'Vid\u00e9o',        action:() => postVideoRef.current?.click() },\n              { icon:<HiUserAdd size={22} color=\"#1877F2\"/>,     label:'Identifier des personnes', action:() => setGpTagOpen(true) },\n              { icon:<span style={{ fontSize:22 }}>\ud83d\udccd</span>,     label: gpLocation ? `Lieu : ${gpLocation}` : 'Ajouter un lieu', action:() => setGpLocationOpen(true) },\n              { icon:<span style={{ fontSize:22 }}>\ud83d\ude0a</span>,     label: gpMood || 'Humeur / Activit\u00e9', action:() => setGpMoodOpen(true) },\n            ].map((opt, i) => (\n              <button key={i} onClick={opt.action}\n                style={{ width:'100%', display:'flex', alignItems:'center', gap:14, padding:'13px 16px', background:'none', border:'none', borderTop: i>0?'1px solid #F0F2F5':'none', cursor:'pointer', textAlign:'left', fontFamily:'Poppins', fontSize:15, fontWeight:600, color:'#050505' }}>\n                {opt.icon} {opt.label}\n              </button>\n            ))}\n          </div>\n      </div>\n      </div>\n      )}\n\n      {/* \u2500\u2500 Modal : Ajouter un membre \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */}\n      {addMemberOpen && (\n        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 400, display: 'flex', alignItems: 'flex-end', justifyContent: 'center' }} onClick={() => setAddMemberOpen(false)}>\n          <div onClick={e => e.stopPropagation()} style={{ background: 'white', borderRadius: '20px 20px 0 0', padding: 20, width: '100%', maxWidth: 480, maxHeight: '80vh', overflowY: 'auto' }}>\n            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}>\n              <h3 style={{ fontWeight: 800, color: '#1877F2', fontSize: 16 }}>Ajouter un membre</h3>\n              <button onClick={() => setAddMemberOpen(false)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#65676B' }}><HiX size={20} /></button>\n            </div>\n\n            <button onClick={copyInviteLink} className=\"btn-secondary\" style={{ width: '100%', padding: '10px 0', fontSize: 13, borderRadius: 10, marginBottom: 14, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8 }}>\n              \ud83d\udd17 Copier / envoyer le lien d'invitation\n            </button>\n\n            <div style={{ position: 'relative', marginBottom: 10 }}>\n              <HiSearch style={{ position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: '#65676B' }} />\n              <input className=\"input\" placeholder=\"Rechercher un ami...\" value={memberSearch} onChange={e => setMemberSearch(e.target.value)} style={{ paddingLeft: 34 }} />\n            </div>\n\n            {friendsList.length === 0 && (\n              <p style={{ fontSize: 13, color: '#65676B', textAlign: 'center', padding: '16px 0' }}>\n                Tous vos amis sont d\u00e9j\u00e0 membres, ou vous n'avez pas encore d'amis \u00e0 inviter directement.\n              </p>\n            )}\n            {friendsList\n              .filter(f => !memberSearch.trim() || f.fullName?.toLowerCase().includes(memberSearch.trim().toLowerCase()))\n              .map(f => (\n                <label key={f.uid} style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '9px 4px', cursor: 'pointer', borderBottom: '1px solid #F0F2F5' }}>\n                  <input type=\"checkbox\" checked={!!selectedFriends[f.uid]} onChange={e => setSelectedFriends(p => ({ ...p, [f.uid]: e.target.checked }))}\n                    style={{ width: 18, height: 18, accentColor: '#1877F2' }} />\n                  <img src={f.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(f.fullName || 'U')}&background=1877F2&color=fff`} alt=\"\" style={{ width: 36, height: 36, borderRadius: '50%', objectFit: 'cover' }} />\n                  <div>\n                    <p style={{ fontWeight: 600, fontSize: 14 }}>{f.fullName}</p>\n                    <p style={{ fontSize: 12, color: '#65676B' }}>@{f.username}</p>\n                  </div>\n                </label>\n              ))}\n\n            {friendsList.length > 0 && (\n              <button onClick={addSelectedMembers} disabled={addingMembers || Object.values(selectedFriends).every(v => !v)} className=\"btn-primary\"\n                style={{ width: '100%', marginTop: 14, padding: '12px 0', fontSize: 15 }}>\n                {addingMembers ? 'Ajout...' : 'Ajouter au groupe'}\n              </button>\n            )}\n          </div>\n        </div>\n      )}\n\n      {/* \u2500\u2500 Modal : Modifier le groupe (admin) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */}\n      {editOpen && (\n        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 400, display: 'flex', alignItems: 'flex-end', justifyContent: 'center' }} onClick={() => setEditOpen(false)}>\n          <div onClick={e => e.stopPropagation()} style={{ background: 'white', borderRadius: '20px 20px 0 0', padding: 20, width: '100%', maxWidth: 480, maxHeight: '85vh', overflowY: 'auto' }}>\n            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}>\n              <h3 style={{ fontWeight: 800, color: '#1877F2' }}>Modifier le groupe</h3>\n              <button onClick={() => setEditOpen(false)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#65676B' }}><HiX size={20} /></button>\n            </div>\n            <p style={{ fontSize: 12, fontWeight: 700, color: '#65676B', marginBottom: 6 }}>NOM DU GROUPE</p>\n            <input className=\"input\" value={editName} onChange={e => setEditName(e.target.value)} maxLength={60} style={{ marginBottom: 10 }} />\n            <p style={{ fontSize: 12, fontWeight: 700, color: '#65676B', marginBottom: 6 }}>DESCRIPTION</p>\n            <textarea className=\"input\" value={editDesc} onChange={e => setEditDesc(e.target.value)} rows={3} maxLength={300} style={{ resize: 'none', borderRadius: 14 }} />\n            <button onClick={saveEdit} disabled={savingEdit} className=\"btn-blue\" style={{ width: '100%', marginTop: 12, padding: '11px 0', fontSize: 14, borderRadius: 10 }}>\n              {savingEdit ? 'Enregistrement...' : 'Enregistrer'}\n            </button>\n            <p style={{ fontSize: 11, color: '#65676B', marginTop: 6, textAlign: 'center' }}>La photo et la couverture se changent avec les boutons \ud83d\udcf7 sur la page.</p>\n\n            <p style={{ fontSize: 12, fontWeight: 700, color: '#65676B', margin: '16px 0 6px' }}>MEMBRES & ADMINS</p>\n            {allMembers.length === 0 && <p style={{ fontSize: 13, color: '#65676B' }}>Chargement des membres...</p>}\n            {allMembers.map(m => {\n              const mAdmin = group.admins?.includes(m.uid);\n              return (\n                <div key={m.uid} style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '8px 0', borderBottom: '1px solid #F0F2F5' }}>\n                  <img src={m.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(m.fullName || 'U')}&background=1877F2&color=fff`} alt=\"\" style={{ width: 36, height: 36, borderRadius: '50%', objectFit: 'cover' }} />\n                  <div style={{ flex: 1, minWidth: 0 }}>\n                    <p style={{ fontWeight: 600, fontSize: 14, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>\n                      {m.fullName}{m.uid === currentUser.uid ? ' (vous)' : ''}\n                    </p>\n                    {mAdmin && <span style={{ fontSize: 10, fontWeight: 700, color: '#F2B300' }}>ADMIN</span>}\n                  </div>\n                  <button onClick={() => toggleAdmin(m.uid)}\n                    className={mAdmin ? 'btn-secondary' : 'btn-gold'}\n                    style={{ padding: '6px 12px', fontSize: 11, borderRadius: 10, flexShrink: 0 }}>\n                    {mAdmin ? 'Retirer admin' : 'Nommer admin'}\n                  </button>\n                </div>\n              );\n            })}\n          </div>\n        </div>\n      )}\n\n      {/* \u2500\u2500 Fil du groupe \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */}\n      {posts.length === 0 && (\n        <div style={{ padding: 30, textAlign: 'center', color: '#65676B', fontSize: 14 }}>\n          Aucune publication dans ce groupe pour le moment.\n        </div>\n      )}\n      {posts.slice(0, visibleCount).map(post => {\n        const rc = {}; Object.values(post.reactions || {}).forEach(e => { rc[e] = (rc[e] || 0) + 1; });\n        const total = Object.keys(post.reactions || {}).length;\n        const myR = post.reactions?.[currentUser.uid];\n        return (\n          <div key={post.id} className=\"card post-card animate-fade\" style={{ marginBottom: 8 }}>\n            <div style={{ padding: '12px 16px 0', display: 'flex', alignItems: 'center', gap: 10 }}>\n              <img src={post.authorPhoto || `https://ui-avatars.com/api/?name=${encodeURIComponent(post.authorName || 'U')}&background=1877F2&color=fff`}\n                alt=\"\" className=\"avatar\" style={{ width: 40, height: 40, cursor: 'pointer' }} onClick={() => post.shopId ? navigate(`/shop/${post.shopId}`) : post.artistId ? navigate(`/artists/${post.artistId}`) : navigate(`/profile/${post.uid}`)} />\n              <div style={{ flex: 1, minWidth: 0 }}>\n                <p style={{ fontWeight: 700, fontSize: 14, cursor: 'pointer' }} onClick={() => post.shopId ? navigate(`/shop/${post.shopId}`) : post.artistId ? navigate(`/artists/${post.artistId}`) : navigate(`/profile/${post.uid}`)}>{post.authorName}{post.shopId ? ' \ud83c\udfea' : ''}</p>\n                <p style={{ fontSize: 12, color: '#65676B' }}>{post.createdAt ? timeAgo(post.createdAt) : \"\u00c0 l'instant\"}</p>\n                {post.taggedNames?.length > 0 && <p style={{ fontSize:12, color:'#65676B' }}>avec {post.taggedNames.join(', ')}</p>}\n                {(post.mood || post.location) && (\n                  <p style={{ fontSize:12, color:'#65676B' }}>\n                    {post.mood && <>{post.mood}</>}{post.mood && post.location ? ' \u00e0 ' : ''}{post.location && <>\ud83d\udccd {post.location}</>}\n                  </p>\n                )}\n              </div>\n              {(post.uid === currentUser.uid || post.mediaURL) && (\n                <div style={{ position: 'relative' }} onClick={e => e.stopPropagation()}>\n                  <button onClick={() => setPostMenu(p => p === post.id ? null : post.id)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#65676B', padding: 4 }}>\n                    <HiDotsVertical size={18} />\n                  </button>\n                  {postMenu === post.id && (\n                    <div style={{ position: 'absolute', top: '100%', right: 0, background: 'white', border: '1px solid #E4E6EB', borderRadius: 12, boxShadow: '0 4px 20px rgba(0,0,0,.14)', minWidth: 170, zIndex: 20, overflow: 'hidden' }}>\n                      {post.mediaURL && (\n                        <button onClick={() => { downloadMedia(post.mediaURL, post.mediaType); setPostMenu(null); }} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '11px 16px', background: 'none', border: 'none', cursor: 'pointer', color: '#050505', fontSize: 14, fontFamily: 'Poppins', borderBottom: (post.uid === currentUser.uid || isAdmin) ? '1px solid #F0F2F5' : 'none' }}>\n                          <HiDownload size={15} color=\"#1877F2\" /> T\u00e9l\u00e9charger\n                        </button>\n                      )}\n                      {(post.uid === currentUser.uid || isAdmin) && (\n                        <button onClick={() => deletePostInGroup(post)} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '11px 16px', background: 'none', border: 'none', cursor: 'pointer', color: '#FF2D8D', fontSize: 14, fontFamily: 'Poppins' }}>\n                          <HiTrash size={15} /> Supprimer\n                        </button>\n                      )}\n                    </div>\n                  )}\n                </div>\n              )}\n            </div>\n            <div style={{ padding: '8px 16px', cursor: 'pointer' }} onClick={() => navigate(`/post/${post.id}`)}>\n              {post.content && (post.textBg ? <p style={{ background: post.textBg, minHeight:180, display:'flex', alignItems:'center', justifyContent:'center', textAlign:'center', color:'#fff', fontSize:24, fontWeight:800, padding:'24px 18px', lineHeight:1.4, wordBreak:'break-word', whiteSpace:'pre-wrap', margin:0, borderRadius:8 }}>{post.content}</p> : <p style={{ fontSize: 15, lineHeight: 1.6, wordBreak: 'break-word' }}>{post.content}</p>)}\n              {post.sharedFrom && (\n                <div onClick={e => { e.stopPropagation(); navigate(`/post/${post.sharedFrom.id}`); }}\n                  style={{ marginTop: 8, border: '1px solid #E4E6EB', borderRadius: 12, overflow: 'hidden', cursor: 'pointer' }}>\n                  <div style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '9px 12px' }}>\n                    <img src={post.sharedFrom.authorPhoto || `https://ui-avatars.com/api/?name=${encodeURIComponent(post.sharedFrom.authorName || 'U')}&background=1877F2&color=fff`}\n                      alt=\"\" style={{ width: 30, height: 30, borderRadius: '50%', objectFit: 'cover' }} />\n                    <p style={{ fontWeight: 700, fontSize: 13 }}>{post.sharedFrom.groupName ? `${post.sharedFrom.groupName} \u00b7 ${post.sharedFrom.authorName}` : post.sharedFrom.authorName}</p>\n                  </div>\n                  {post.sharedFrom.content && <p style={{ padding: '0 12px 8px', fontSize: 13, color: '#050505' }}>{post.sharedFrom.content}</p>}\n                  {post.sharedFrom.mediaURL && (\n                    post.sharedFrom.isMusic\n                      ? <div style={{ padding: '0 10px 10px' }}><MusicPostCard post={post.sharedFrom} height={110} /></div>\n                      : post.sharedFrom.mediaType === 'image'\n                        ? <img src={post.sharedFrom.mediaURL} alt=\"\" style={{ width: '100%', maxHeight: 320, objectFit: 'cover', display: 'block' }} />\n                        : <video src={post.sharedFrom.mediaURL} muted playsInline style={{ width: '100%', maxHeight: 320, objectFit: 'cover', display: 'block', background: '#000' }} />\n                  )}\n                </div>\n              )}\n              {post.mediaURL && (\n                <div style={{ marginTop: 8, marginLeft: -16, marginRight: -16 }}>\n                  {post.isMusic\n                    ? <MusicPostCard post={post} />\n                    : post.mediaType === 'image'\n                      ? <img src={post.mediaURL} alt=\"\" onClick={() => setViewerState({ post, index: 0 })} style={{ width: '100%', maxHeight: 520, objectFit: 'cover', display: 'block', cursor: 'zoom-in' }} />\n                      : <video src={post.mediaURL} controls playsInline poster={post.thumbURL || undefined} preload={dataSaver ? 'none' : 'metadata'} style={{ width: '100%', maxHeight: 520, display: 'block', background: '#000' }} />}\n                </div>\n              )}\n              {/* \u2500\u2500 Article boutique : informations ambanin'ny sary (sary 3) \u2500\u2500 */}\n              {post.shopId && post.isSale && (\n                <div onClick={e => e.stopPropagation()} style={{ marginTop: 10 }}>\n                  <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 10 }}>\n                    <span style={{ fontWeight: 800, fontSize: 20, color: '#FF2D8D' }}>{post.price ? `${Number(post.price).toLocaleString()} Ar` : '\u00c0 discuter'}</span>\n                    <button onClick={() => navigate(`/shop/${post.shopId}/messages`)}\n                      style={{ display: 'flex', alignItems: 'center', gap: 5, background: '#fff', border: '1.5px solid #FF2D8D', borderRadius: 20, padding: '7px 16px', fontSize: 13, fontWeight: 700, color: '#FF2D8D', cursor: 'pointer', flexShrink: 0 }}>\n                      <NeonPlaneWhite size={15}/> Message\n                    </button>\n                  </div>\n                  {(post.lieu || post.contact) && (\n                    <div style={{ display: 'flex', alignItems: 'center', flexWrap: 'wrap', gap: 8, marginTop: 8, paddingTop: 8, borderTop: '1px solid #F0F2F5' }}>\n                      {post.lieu && <span style={{ display: 'flex', alignItems: 'center', gap: 5, background: '#F0F2F5', borderRadius: 20, padding: '5px 12px', color: '#65676B', fontSize: 13 }}><HiLocationMarker size={13} color=\"#1877F2\"/>{post.lieu}</span>}\n                      {post.contact && <a href={`tel:${String(post.contact).split(/[\\/,;|]/)[0].trim()}`} style={{ display: 'flex', alignItems: 'center', gap: 5, background: '#E4E6EB', borderRadius: 20, padding: '5px 12px', color: '#1877F2', fontSize: 13, fontWeight: 600, textDecoration: 'none' }}><HiPhone size={13}/>{post.contact}</a>}\n                    </div>\n                  )}\n                  <button onClick={() => { const ok = addToCart(post); alert(ok ? 'Article ajout\u00e9 au panier \ud83d\uded2' : 'Cet article est d\u00e9j\u00e0 dans votre panier'); }}\n                    style={{ width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 7, background: 'linear-gradient(145deg,#FF6FA5,#FF2D8D)', border: 'none', borderRadius: 20, padding: '10px 0', marginTop: 10, fontSize: 14, fontWeight: 800, color: '#fff', cursor: 'pointer', fontFamily: 'Poppins' }}>\n                    <HiShoppingCart size={17}/> Ajouter au panier\n                  </button>\n                </div>\n              )}\n            </div>\n            {total > 0 && (\n              <div style={{ padding: '4px 16px 6px', display: 'flex', alignItems: 'center', gap: 4 }}>\n                <div style={{ display: 'flex' }}>{Object.keys(rc).slice(0, 3).map((e, i) => <span key={e} style={{ fontSize: 15, marginLeft: i ? -3 : 0 }}>{e}</span>)}</div>\n                <span style={{ fontSize: 13, color: '#65676B' }}>{total}</span>\n              </div>\n            )}\n            <div className='post-actions-row'>\n              <div style={{ position: 'relative', flex: 1, display: 'flex' }}>\n                <button onClick={() => reactToPost(post.id, myR || '\ud83d\udc4d')}\n                  onContextMenu={e => { e.preventDefault(); setShowReact(p => ({ ...p, [post.id]: !p[post.id] })); }}\n                  className={'post-action-btn' + (myR ? ' active' : '')}\n                  style={myR ? { color: myR === '\ud83d\udc4d' ? '#1877F2' : '#FF2D8D', fontWeight: 700 } : {}}>\n                  <span style={{ fontSize: 17 }}>{myR || '\ud83d\udc4d'}</span> J'aime\n                </button>\n                {showReact[post.id] && (\n                  <div style={{ position: 'absolute', bottom: '110%', left: 8, background: 'white', borderRadius: 30, padding: '8px 12px', display: 'flex', gap: 6, boxShadow: '0 4px 20px rgba(0,0,0,.2)', zIndex: 10, border: '1px solid #E4E6EB' }}>\n                    {REACTIONS.map(e => <button key={e} onClick={() => reactToPost(post.id, e)} style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: 24 }}>{e}</button>)}\n                  </div>\n                )}\n              </div>\n              <button onClick={() => navigate(`/post/${post.id}`)} className='post-action-btn'>\n                <HiChat size={18} /> Commenter{post.comments?.length > 0 ? ` (${post.comments.length})` : ''}\n              </button>\n              <button onClick={() => sharePost(post)} className='post-action-btn'>\n                <HiShare size={18} /> Partager\n              </button>\n            </div>\n          </div>\n        );\n      })}\n\n      {viewerState && (\n        <MediaViewer\n          post={viewerState.post}\n          startIndex={viewerState.index}\n          onClose={() => setViewerState(null)}\n          currentUser={currentUser}\n          userProfile={userProfile}\n          navigate={navigate}\n          myR={viewerState.post.reactions?.[currentUser.uid]}\n          rc={(() => { const c={}; Object.values(viewerState.post.reactions||{}).forEach(e=>{c[e]=(c[e]||0)+1;}); return c; })()}\n          total={Object.keys(viewerState.post.reactions||{}).length}\n          onReact={(emoji) => reactToPost(viewerState.post.id, emoji)}\n          onDownload={(url) => downloadMedia(url, 'image')}\n          onShare={() => sharePost(viewerState.post)}\n        />\n      )}\n      {shareModalPost && <ShareModal post={shareModalPost} onClose={() => setShareModalPost(null)} />}\n\n      {/* \u2500\u2500 Bottom sheet : Plus d'options (groupe) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */}\n      {gpMoreOpen && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', zIndex:420, display:'flex', alignItems:'flex-end', justifyContent:'center' }} onClick={() => setGpMoreOpen(false)}>\n          <div onClick={e => e.stopPropagation()} style={{ background:'white', borderRadius:'20px 20px 0 0', padding:'8px 0 20px', width:'100%', maxWidth:480 }}>\n            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', padding:'10px 20px 14px' }}>\n              <h3 style={{ fontWeight:800, fontSize:16 }}>Plus d'options</h3>\n              <button onClick={() => setGpMoreOpen(false)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={20}/></button>\n            </div>\n            {[\n              { icon:<HiUserAdd size={20} color=\"#1877F2\"/>, label:'Identifier des personnes', action:() => { setGpMoreOpen(false); openGpTagModal(); } },\n              { icon:<span style={{ fontSize:20 }}>\ud83d\udccd</span>, label: gpLocation ? `Lieu : ${gpLocation}` : 'Ajouter un lieu', action:() => { setGpMoreOpen(false); setGpLocationOpen(true); } },\n              { icon:<span style={{ fontSize:20 }}>\ud83d\ude0a</span>, label: gpMood || 'Humeur / Activit\u00e9', action:() => { setGpMoreOpen(false); setGpMoodOpen(true); } },\n              { icon:<HiChat size={20} color=\"#1877F2\"/>, label: gpAllowMessages ? 'Recevoir des messages : Activ\u00e9' : 'Recevoir des messages : D\u00e9sactiv\u00e9', action:() => setGpAllowMessages(p => !p) },\n            ].map((item, i) => (\n              <button key={i} onClick={item.action} style={{ width:'100%', display:'flex', alignItems:'center', gap:14, padding:'13px 20px', background:'none', border:'none', cursor:'pointer', fontFamily:'Poppins', fontSize:15, fontWeight:600, color:'#050505', textAlign:'left' }}>\n                {item.icon} {item.label}\n              </button>\n            ))}\n          </div>\n        </div>\n      )}\n\n      {gpLocationOpen && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', zIndex:430, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }} onClick={() => setGpLocationOpen(false)}>\n          <div onClick={e => e.stopPropagation()} style={{ background:'white', borderRadius:18, padding:20, width:'100%', maxWidth:360 }}>\n            <h3 style={{ fontWeight:800, fontSize:15, marginBottom:12 }}>\ud83d\udccd Ajouter un lieu</h3>\n            <input className=\"input\" autoFocus placeholder=\"O\u00f9 \u00eates-vous ?\" value={gpLocation} onChange={e => setGpLocation(e.target.value)} maxLength={100} style={{ marginBottom:14 }}/>\n            <button onClick={() => setGpLocationOpen(false)} className=\"btn-primary\" style={{ width:'100%', padding:'10px 0', fontSize:14 }}>OK</button>\n          </div>\n        </div>\n      )}\n\n      {gpMoodOpen && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', zIndex:430, display:'flex', alignItems:'flex-end', justifyContent:'center' }} onClick={() => setGpMoodOpen(false)}>\n          <div onClick={e => e.stopPropagation()} style={{ background:'white', borderRadius:'20px 20px 0 0', padding:20, width:'100%', maxWidth:480 }}>\n            <h3 style={{ fontWeight:800, fontSize:15, marginBottom:12 }}>Comment vous sentez-vous ?</h3>\n            {MOODS.map(m => (\n              <button key={m} onClick={() => { setGpMood(m); setGpMoodOpen(false); }}\n                style={{ width:'100%', textAlign:'left', padding:'11px 6px', background:'none', border:'none', borderBottom:'1px solid #F0F2F5', cursor:'pointer', fontSize:15, fontFamily:'Poppins' }}>\n                {m}\n              </button>\n            ))}\n          </div>\n        </div>\n      )}\n\n      {gpTagOpen && (\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', zIndex:430, display:'flex', alignItems:'flex-end', justifyContent:'center' }} onClick={() => setGpTagOpen(false)}>\n          <div onClick={e => e.stopPropagation()} style={{ background:'white', borderRadius:'20px 20px 0 0', padding:20, width:'100%', maxWidth:480, maxHeight:'75vh', overflowY:'auto' }}>\n            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>\n              <h3 style={{ fontWeight:800, fontSize:16 }}>Identifier des amis</h3>\n              <button onClick={() => setGpTagOpen(false)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={20}/></button>\n            </div>\n            {gpTagList.length === 0 && <p style={{ fontSize:13, color:'#65676B', textAlign:'center', padding:'16px 0' }}>Vous n'avez pas encore d'amis \u00e0 identifier.</p>}\n            {gpTagList.map(f => (\n              <label key={f.uid} style={{ display:'flex', alignItems:'center', gap:10, padding:'9px 4px', cursor:'pointer', borderBottom:'1px solid #F0F2F5' }}>\n                <input type=\"checkbox\" checked={!!gpTagSel[f.uid]} onChange={e => setGpTagSel(p => ({ ...p, [f.uid]: e.target.checked }))} style={{ width:18, height:18, accentColor:'#1877F2' }}/>\n                <img src={f.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(f.fullName||'U')}&background=1877F2&color=fff`} alt=\"\" style={{ width:36, height:36, borderRadius:'50%', objectFit:'cover' }}/>\n                <p style={{ fontWeight:600, fontSize:14 }}>{f.fullName}</p>\n              </label>\n            ))}\n            <button onClick={() => setGpTagOpen(false)} className=\"btn-primary\" style={{ width:'100%', marginTop:14, padding:'11px 0', fontSize:14 }}>OK</button>\n          </div>\n        </div>\n      )}\n      {posts.length > visibleCount && (\n        <div ref={el => { if (!el) return; const io = new IntersectionObserver(es => { if (es[0].isIntersecting) setVisibleCount(c => c + 10); }, { rootMargin: '400px' }); io.observe(el); }}\n          style={{ padding: 18, textAlign: 'center', color: '#65676B', fontSize: 13 }}>Chargement\u2026</div>\n      )}\n    </div>\n  );\n}\n";
const POSTDETAIL_SRC="// src/pages/PostDetail.jsx\nimport { useState, useEffect, useRef } from 'react';\nimport { useParams, useNavigate } from 'react-router-dom';\nimport {\n  doc, onSnapshot, updateDoc, addDoc, serverTimestamp,\n  arrayUnion, arrayRemove, collection, getDoc\n} from 'firebase/firestore';\nimport { db } from '../firebase';\nimport { NeonPlaneWhite } from '../components/NeonIcons';\nimport MusicPostCard from '../components/MusicPostCard';\nimport { useAuth } from '../context/AuthContext';\nimport { timeAgo } from '../utils/timeAgo';\nimport { downloadMedia } from '../utils/download';\nimport ShareModal from '../components/ShareModal';\nimport { SkeletonSinglePost } from '../components/Skeleton';\nimport PhotoCarousel from '../components/PhotoCarousel';\nimport MediaViewer from '../components/MediaViewer';\nimport { useLang } from '../context/LanguageContext';\nimport { uploadToTelegram } from '../utils/telegram';\nimport { getChatId } from '../utils/chat';\nimport { v4 as uuidv4 } from 'uuid';\nimport {\n  HiArrowLeft, HiOutlineHeart, HiChat, HiShare, HiUserGroup, HiIdentification, HiShoppingBag,\n  HiPhotograph, HiVideoCamera, HiTag, HiX, HiPhone, HiShoppingCart,\n  HiLocationMarker, HiPencil, HiTrash, HiReply, HiUserAdd, HiDownload, HiPaperAirplane\n} from 'react-icons/hi';\nimport { addToCart } from '../utils/cart';\n\nconst REACTIONS = ['\u2764\ufe0f','\ud83d\ude02','\ud83d\ude2e','\ud83d\ude22','\ud83d\ude21'];\nfunction VIPBadge() {\n  return <img src='/vip-badge.png' style={{ width:24, height:24, marginLeft:5, verticalAlign:'middle', display:'inline-block', flexShrink:0, objectFit:'contain' }} alt='VIP'/>;\n}\n\nexport default function PostDetail() {\n  const { postId }  = useParams();\n  const { currentUser, userProfile } = useAuth();\n  const { t }       = useLang();\n  const navigate    = useNavigate();\n\n  const [post,          setPost]       = useState(null);\n  const [showReactions, setShowReact]  = useState(false);\n  const [reactionModal, setRM]         = useState(null);\n  const [commentText,   setCmtText]    = useState('');\n  const [commentMedia,  setCmtMedia]   = useState(null);\n  const [editCmt,       setEditCmt]    = useState(null);\n  const [replyTo,       setReplyTo]    = useState(null);\n  const [cmtReactPicker, setCmtReactPicker] = useState(null);\n  const [viewerState,   setViewerState] = useState(null); // { index }\n  const cPhotoRef = useRef(); const cVideoRef = useRef();\n\n  useEffect(() => {\n    if (!postId) return;\n    return onSnapshot(doc(db,'posts',postId), snap => { if (snap.exists()) setPost({id:snap.id,...snap.data()}); });\n  }, [postId]);\n\n  async function reactToPost(emoji) {\n    const r = post.reactions||{}, my = r[currentUser.uid];\n    if (my===emoji) { const u={...r}; delete u[currentUser.uid]; await updateDoc(doc(db,'posts',postId),{reactions:u}); }\n    else {\n      await updateDoc(doc(db,'posts',postId),{[`reactions.${currentUser.uid}`]:emoji});\n      if (post.uid!==currentUser.uid) {\n        await addDoc(collection(db,'notifications'), { toUid:post.uid, fromUid:currentUser.uid, fromName:userProfile.fullName, fromPhoto:userProfile.photoURL||'', type:'reaction', postId, emoji, message:`${userProfile.fullName} a r\u00e9agi ${emoji}`, read:false, createdAt:serverTimestamp() });\n      }\n    }\n    setShowReact(false);\n  }\n\n  async function submitViewerComment(text) {\n    const v = (text||'').trim();\n    if (!v || !post) return;\n    const cmt = { id:uuidv4(), uid:currentUser.uid, authorName:userProfile.fullName, authorPhoto:userProfile.photoURL||'', authorIsVip:userProfile.isVip||false, text:v.slice(0,500), mediaURL:'', mediaType:'', createdAt:new Date().toISOString() };\n    await updateDoc(doc(db,'posts',postId), { comments:arrayUnion(cmt) });\n    if (post.uid!==currentUser.uid) {\n      await addDoc(collection(db,'notifications'), { toUid:post.uid, fromUid:currentUser.uid, fromName:userProfile.fullName, fromPhoto:userProfile.photoURL||'', type:'comment', postId, message:`${userProfile.fullName} a comment\u00e9 votre publication`, read:false, createdAt:serverTimestamp() });\n    }\n  }\n\n  async function openRM() {\n    const r = post.reactions||{}; if (!Object.keys(r).length) return;\n    const ud = {};\n    await Promise.all(Object.keys(r).map(async uid => {\n      try { const s=await getDoc(doc(db,'users',uid)); ud[uid]=s.exists()?{name:s.data().fullName,photo:s.data().photoURL}:{name:uid,photo:''}; } catch { ud[uid]={name:uid,photo:''}; }\n    }));\n    setRM({reactions:r,userData:ud});\n  }\n\n  async function addComment() {\n    const rt   = replyTo;\n    const raw  = rt ? `@${rt} ${commentText}` : commentText;\n    const text = raw.trim(); const media = commentMedia;\n    if (!text&&!media) return;\n    let mediaURL='', mT='';\n    if (media) { try { const r=await uploadToTelegram(media.file); mediaURL=r.url; mT=r.type; } catch {} }\n    const cmt = { id:uuidv4(), uid:currentUser.uid, authorName:userProfile.fullName, authorPhoto:userProfile.photoURL||'', authorIsVip:userProfile.isVip||false, text:text.slice(0,500), mediaURL, mediaType:mT, createdAt:new Date().toISOString() };\n    await updateDoc(doc(db,'posts',postId), { comments:arrayUnion(cmt) });\n    setCmtText(''); setCmtMedia(null); setReplyTo(null);\n    if (post.uid!==currentUser.uid) {\n      await addDoc(collection(db,'notifications'), { toUid:post.uid, fromUid:currentUser.uid, fromName:userProfile.fullName, fromPhoto:userProfile.photoURL||'', type:'comment', postId, message:`${userProfile.fullName} a comment\u00e9 votre publication`, read:false, createdAt:serverTimestamp() });\n    }\n  }\n\n  async function deleteCmt(cmt) {\n    if (cmt.uid!==currentUser.uid && post.uid!==currentUser.uid) return;\n    if (!window.confirm('Supprimer ce commentaire ?')) return;\n    await updateDoc(doc(db,'posts',postId), { comments:arrayRemove(cmt) });\n  }\n\n  async function saveEditCmt(oldCmt, newText) {\n    if (oldCmt.uid !== currentUser.uid) return;\n    if (!newText.trim()) return;\n    const updated = post.comments.map(c => c.id===oldCmt.id?{...c,text:newText.trim()}:c);\n    await updateDoc(doc(db,'posts',postId), { comments:updated });\n    setEditCmt(null);\n  }\n\n  async function reactToCmt(cmtId, emoji) {\n    const updated = post.comments.map(c => {\n      if (c.id!==cmtId) return c;\n      const reactions = c.reactions||{}, my = reactions[currentUser.uid];\n      if (my===emoji) { const u={...reactions}; delete u[currentUser.uid]; return {...c,reactions:u}; }\n      return {...c,reactions:{...reactions,[currentUser.uid]:emoji}};\n    });\n    await updateDoc(doc(db,'posts',postId),{comments:updated});\n    setCmtReactPicker(null);\n  }\n\n  function sharePost() {\n    setShareModalOpen(true);\n  }\n\n  function isFriend(uid) { return (userProfile?.friends||[]).includes(uid); }\n  const [shareModalOpen, setShareModalOpen] = useState(false);\n\n  if (!post) return <SkeletonSinglePost />;\n\n  const myR   = post.reactions?.[currentUser.uid];\n  const total = Object.keys(post.reactions||{}).length;\n  const rc    = {};\n  Object.values(post.reactions||{}).forEach(e => { rc[e]=(rc[e]||0)+1; });\n\n  return (\n    <div style={{ padding:'16px 12px' }}>\n      <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:14 }}>\n        <button onClick={() => navigate(-1)} style={{ background:'none', border:'none', cursor:'pointer', color:'#1877F2' }}><HiArrowLeft size={22}/></button>\n        <h2 style={{ fontWeight:700, fontSize:18, color:'#1877F2' }}>Publication</h2>\n      </div>\n\n      {/* Reaction modal */}\n      {reactionModal&&(\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.5)', zIndex:820, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>\n          <div className=\"card\" style={{ width:'100%', maxWidth:360, padding:20, maxHeight:'70vh', overflowY:'auto' }}>\n            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>\n              <h3 style={{ color:'#1877F2' }}>R\u00e9actions</h3>\n              <button onClick={() => setRM(null)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={20}/></button>\n            </div>\n            {Object.entries(reactionModal.reactions).map(([uid,emoji]) => {\n              const info = reactionModal.userData?.[uid]||{};\n              return (\n                <div key={uid} onClick={() => { setRM(null); navigate(`/profile/${uid}`); }} style={{ display:'flex', alignItems:'center', gap:10, padding:'8px 0', borderBottom:'1px solid #E4E6EB', cursor:'pointer' }}>\n                  <img src={info.photo||`https://ui-avatars.com/api/?name=${encodeURIComponent(info.name||'U')}&background=1877F2&color=fff`} alt=\"\" style={{ width:36, height:36, borderRadius:'50%', objectFit:'cover' }}/>\n                  <p style={{ fontSize:14, fontWeight:600, flex:1 }}>{uid===currentUser.uid?'Vous':(info.name||uid)}</p>\n                  <span style={{ fontSize:20 }}>{emoji}</span>\n                </div>\n              );\n            })}\n          </div>\n        </div>\n      )}\n\n      {/* Edit comment modal */}\n      {editCmt&&(\n        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.5)', zIndex:200, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>\n          <div className=\"card\" style={{ width:'100%', maxWidth:400, padding:20 }}>\n            <h3 style={{ marginBottom:12 }}>Modifier le commentaire</h3>\n            <textarea className=\"input\" rows={3} value={editCmt.text} onChange={e=>setEditCmt(p=>({...p,text:e.target.value}))} style={{ resize:'none' }}/>\n            <div style={{ display:'flex', gap:10, marginTop:12 }}>\n              <button className=\"btn-secondary\" onClick={() => setEditCmt(null)} style={{ flex:1 }}>{t('cancel')}</button>\n              <button className=\"btn-primary\" onClick={() => saveEditCmt(editCmt.cmt,editCmt.text)} style={{ flex:1 }}>{t('save')}</button>\n            </div>\n          </div>\n        </div>\n      )}\n\n      <div className=\"card post-card\">\n        {/* Header */}\n        <div style={{ padding:'14px 16px 0', display:'flex', alignItems:'center', justifyContent:'space-between' }}>\n          {post.groupName ? (\n            <div onClick={() => navigate(`/groups/${post.groupId}`)} style={{ display:'flex', alignItems:'center', gap:10, cursor:'pointer', flex:1, minWidth:0 }}>\n              <div style={{ width:42, height:42, borderRadius:10, background:'linear-gradient(145deg,#1B84FF,#1877F2)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0, overflow:'hidden' }}>\n                {post.groupPhoto ? <img src={post.groupPhoto} alt=\"\" style={{ width:'100%', height:'100%', objectFit:'cover' }}/> : <HiUserGroup size={20} color=\"white\"/>}\n              </div>\n              <div><p style={{ fontWeight:700, fontSize:15 }}>{post.groupName}</p><p style={{ fontSize:12, color:'#65676B' }}>Groupe \u00b7 {post.createdAt?timeAgo(post.createdAt):''}</p></div>\n            </div>\n          ) : post.pageId ? (\n            <div onClick={() => navigate(`/pages/${post.pageId}`)} style={{ display:'flex', alignItems:'center', gap:10, cursor:'pointer', flex:1, minWidth:0 }}>\n              <div style={{ width:42, height:42, borderRadius:10, background:'linear-gradient(145deg,#63A9FF,#1877F2)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0, overflow:'hidden' }}>\n                {post.pagePhoto ? <img src={post.pagePhoto} alt=\"\" style={{ width:'100%', height:'100%', objectFit:'cover' }}/> : <HiIdentification size={20} color=\"white\"/>}\n              </div>\n              <div><p style={{ fontWeight:700, fontSize:15 }}>{post.pageName}</p><p style={{ fontSize:12, color:'#65676B' }}>Sera \u00b7 {post.createdAt?timeAgo(post.createdAt):''}</p></div>\n            </div>\n          ) : post.artistId ? (\n            <div onClick={() => navigate(`/artists/${post.artistId}`)} style={{ display:'flex', alignItems:'center', gap:10, cursor:'pointer', flex:1, minWidth:0 }}>\n              <div style={{ width:42, height:42, borderRadius:'50%', background:'linear-gradient(145deg,#FF6FA5,#FF2D8D)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0, overflow:'hidden' }}>\n                {post.artistPhoto ? <img src={post.artistPhoto} alt=\"\" style={{ width:'100%', height:'100%', objectFit:'cover' }}/> : <span style={{ color:'white' }}>\ud83c\udfa4</span>}\n              </div>\n              <div><p style={{ fontWeight:700, fontSize:15 }}>{post.artistName} \ud83c\udfa4</p><p style={{ fontSize:12, color:'#65676B' }}>{post.genre} \u00b7 {post.createdAt?timeAgo(post.createdAt):''}</p></div>\n            </div>\n          ) : post.shopId ? (\n            <div onClick={() => navigate(`/shop/${post.shopId}`)} style={{ display:'flex', alignItems:'center', gap:10, cursor:'pointer', flex:1, minWidth:0 }}>\n              <div style={{ width:42, height:42, borderRadius:10, background:'linear-gradient(145deg,#FF6FA5,#FF2D8D)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0, overflow:'hidden' }}>\n                {post.shopPhoto ? <img src={post.shopPhoto} alt=\"\" style={{ width:'100%', height:'100%', objectFit:'cover' }}/> : <HiShoppingBag size={20} color=\"white\"/>}\n              </div>\n              <div><p style={{ fontWeight:700, fontSize:15 }}>{post.shopName} \ud83c\udfea</p><p style={{ fontSize:12, color:'#65676B' }}>Boutique \u00b7 {post.createdAt?timeAgo(post.createdAt):''}</p></div>\n            </div>\n          ) : (\n            <div style={{ display:'flex', alignItems:'center', gap:10, cursor:'pointer', flex:1, minWidth:0 }} onClick={() => navigate(`/profile/${post.uid}`)}>\n              <img src={post.authorPhoto||`https://ui-avatars.com/api/?name=${encodeURIComponent(post.authorName||'U')}&background=1877F2&color=fff`} alt=\"\" className=\"avatar\" style={{ width:42, height:42, flexShrink:0 }}/>\n              <div>\n                <p style={{ fontWeight:700, fontSize:15 }}>{post.authorName}{post.authorIsVip&&<VIPBadge/>}</p>\n                <p style={{ fontSize:12, color:'#65676B' }}>@{post.authorUsername} \u00b7 {post.createdAt?timeAgo(post.createdAt):''}</p>\n              </div>\n            </div>\n          )}\n          {!post.groupName && !post.pageId && !post.artistId && !post.shopId && (\n            <div style={{ display:'flex', gap:6, flexShrink:0 }}>\n              {post.uid!==currentUser.uid&&<button onClick={() => navigate(`/messages/${getChatId(currentUser.uid,post.uid)}`)} style={{ background:'#E4E6EB', border:'none', borderRadius:20, padding:'6px 12px', cursor:'pointer', color:'#1877F2', fontSize:12, fontWeight:600 }}><HiPaperAirplane size={13} style={{ transform:'rotate(90deg)', display:'inline', marginRight:4 }}/>Message</button>}\n              {post.uid!==currentUser.uid&&!isFriend(post.uid)&&!(userProfile?.sentRequests||[]).includes(post.uid)&&(\n                <button onClick={async()=>{\n                  await addDoc(collection(db,'friendRequests'),{fromUid:currentUser.uid,toUid:post.uid,fromName:userProfile.fullName,fromPhoto:userProfile.photoURL||'',status:'pending',createdAt:serverTimestamp()});\n                  alert('Demande envoy\u00e9e !');\n                }} style={{ background:'none', border:'1px solid #E4E6EB', borderRadius:20, padding:'6px 12px', cursor:'pointer', color:'#65676B', fontSize:12, display:'flex', alignItems:'center', gap:4 }}><HiUserAdd size={13}/> Ajouter</button>\n              )}\n            </div>\n          )}\n        </div>\n\n        {/* Content */}\n        {post.shopId && post.isSale ? (\n          // \u2500\u2500 Article boutique (sary 3) : sary lehibe ambony, informations ambany \u2500\u2500\n          <>\n            {post.mediaURL && (\n              <div className=\"post-media\" style={{ position:'relative' }}>\n                <img src={post.mediaURL} alt=\"\" onClick={() => setViewerState({ index: 0 })} style={{ cursor:'zoom-in' }}/>\n                <button onClick={() => downloadMedia(post.mediaURL, 'image')}\n                  style={{ position:'absolute', top:8, right:8, width:34, height:34, borderRadius:'50%', background:'rgba(0,0,0,.5)', border:'none', cursor:'pointer', color:'white', display:'flex', alignItems:'center', justifyContent:'center' }}>\n                  <HiDownload size={16}/>\n                </button>\n              </div>\n            )}\n            <div style={{ padding:'14px 16px' }}>\n              <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:10 }}>\n                <span style={{ fontWeight:800, fontSize:22, color:'#FF2D8D' }}>{post.price ? `${Number(post.price).toLocaleString()} Ar` : '\u00c0 discuter'}</span>\n                <button onClick={() => navigate(`/shop/${post.shopId}/messages`)}\n                  style={{ display:'flex', alignItems:'center', gap:5, background:'#fff', border:'1.5px solid #FF2D8D', borderRadius:20, padding:'8px 18px', fontSize:13.5, fontWeight:700, color:'#FF2D8D', cursor:'pointer', flexShrink:0 }}>\n                  <NeonPlaneWhite size={16}/> Message\n                </button>\n              </div>\n              {Number(post.oldPrice) > Number(post.price) && (\n                <p style={{ fontSize:13, color:'#8A8D91', textDecoration:'line-through', marginTop:2 }}>{Number(post.oldPrice).toLocaleString()} Ar</p>\n              )}\n              {(post.lieu || post.contact) && (\n                <div style={{ display:'flex', flexWrap:'wrap', gap:8, marginTop:10 }}>\n                  {post.lieu && <span style={{ display:'flex', alignItems:'center', gap:5, background:'#F0F2F5', borderRadius:20, padding:'5px 12px', color:'#65676B', fontSize:13 }}><HiLocationMarker size={13} color=\"#1877F2\"/>{post.lieu}</span>}\n                  {post.contact && <a href={`tel:${String(post.contact).split(/[\\/,;|]/)[0].trim()}`} style={{ display:'flex', alignItems:'center', gap:5, background:'#E4E6EB', borderRadius:20, padding:'5px 12px', color:'#1877F2', fontSize:13, fontWeight:600, textDecoration:'none' }}><HiPhone size={13}/>{post.contact}</a>}\n                  {post.saleCategory && <span style={{ display:'flex', alignItems:'center', gap:5, background:'#FFE3EF', borderRadius:20, padding:'5px 12px', color:'#FF2D8D', fontSize:13, fontWeight:600 }}><HiTag size={12}/>{post.saleCategory}</span>}\n                </div>\n              )}\n              {post.content && <p style={{ fontSize:15, lineHeight:1.7, wordBreak:'break-word', marginTop:12 }}>{post.content}</p>}\n              <button onClick={() => { const ok = addToCart(post); alert(ok ? 'Article ajout\u00e9 au panier \ud83d\uded2' : 'Cet article est d\u00e9j\u00e0 dans votre panier'); }}\n                style={{ width:'100%', display:'flex', alignItems:'center', justifyContent:'center', gap:8, background:'linear-gradient(145deg,#FF6FA5,#FF2D8D)', border:'none', borderRadius:22, padding:'12px 0', marginTop:14, fontSize:15, fontWeight:800, color:'#fff', cursor:'pointer', fontFamily:'Poppins' }}>\n                <HiShoppingCart size={18}/> Ajouter au panier\n              </button>\n            </div>\n          </>\n        ) : (\n        <div style={{ padding:'12px 16px' }}>\n          {post.isSale&&<div style={{ display:'flex', gap:10, alignItems:'center', marginBottom:10 }}><span className=\"sale-badge\"><HiTag size={12} style={{ display:'inline' }}/> Vente</span><span className=\"price-tag\">{post.price} Ar</span></div>}\n          {post.isSale&&(post.contact||post.lieu)&&(\n            <div style={{ marginBottom:10, display:'flex', flexWrap:'wrap', gap:8 }}>\n              {post.contact&&<a href={`tel:${post.contact}`} style={{ display:'flex', alignItems:'center', gap:5, background:'#E4E6EB', borderRadius:20, padding:'5px 12px', color:'#1877F2', fontSize:13, fontWeight:600, textDecoration:'none' }}><HiPhone size={13}/>{post.contact}</a>}\n              {post.lieu&&<span style={{ display:'flex', alignItems:'center', gap:5, background:'#F0F2F5', borderRadius:20, padding:'5px 12px', color:'#65676B', fontSize:13 }}><HiLocationMarker size={13} color=\"#1877F2\"/>{post.lieu}</span>}\n            </div>\n          )}\n          {post.content&&(post.textBg ? <p style={{ background: post.textBg, minHeight:180, display:'flex', alignItems:'center', justifyContent:'center', textAlign:'center', color:'#fff', fontSize:24, fontWeight:800, padding:'24px 18px', lineHeight:1.4, wordBreak:'break-word', whiteSpace:'pre-wrap', margin:0, borderRadius:8 }}>{post.content}</p> : <p style={{ fontSize:15, lineHeight:1.7, wordBreak:'break-word', marginBottom:10 }}>{post.content}</p>)}\n          {post.sharedFrom && (\n            <div onClick={() => navigate(`/post/${post.sharedFrom.id}`)}\n              style={{ marginBottom:10, border:'1px solid #E4E6EB', borderRadius:12, overflow:'hidden', cursor:'pointer' }}>\n              <div style={{ display:'flex', alignItems:'center', gap:8, padding:'9px 12px' }}>\n                <img src={post.sharedFrom.authorPhoto||`https://ui-avatars.com/api/?name=${encodeURIComponent(post.sharedFrom.authorName||'U')}&background=1877F2&color=fff`}\n                  alt=\"\" style={{ width:30, height:30, borderRadius:'50%', objectFit:'cover' }}/>\n                <p style={{ fontWeight:700, fontSize:13 }}>{post.sharedFrom.groupName ? `${post.sharedFrom.groupName} \u00b7 ${post.sharedFrom.authorName}` : post.sharedFrom.authorName}</p>\n              </div>\n              {post.sharedFrom.content && <p style={{ padding:'0 12px 8px', fontSize:13, color:'#050505' }}>{post.sharedFrom.content}</p>}\n              {post.sharedFrom.mediaURL && (\n                post.sharedFrom.mediaType === 'image'\n                  ? <img src={post.sharedFrom.mediaURL} alt=\"\" style={{ width:'100%', maxHeight:320, objectFit:'cover', display:'block' }}/>\n                  : <video src={post.sharedFrom.mediaURL} muted playsInline style={{ width:'100%', maxHeight:320, objectFit:'cover', display:'block', background:'#000' }}/>\n              )}\n            </div>\n          )}\n          {post.mediaURLs?.length > 1 ? (\n            <div className=\"post-media\">\n              <PhotoCarousel urls={post.mediaURLs} onOpen={(u) => setViewerState({ index: Math.max(0, post.mediaURLs.indexOf(u)) })} />\n            </div>\n          ) : post.mediaURL&&(\n            <div className=\"post-media\" style={{ position:'relative' }}>\n              {post.isMusic\n                ? <MusicPostCard post={post} height={150}/>\n                : post.mediaType==='image'\n                  ? <img src={post.mediaURL} alt=\"\" onClick={() => setViewerState({ index: 0 })} style={{ cursor:'zoom-in' }}/>\n                  : <video src={post.mediaURL} poster={post.thumbURL || undefined} controls/>}\n              <button onClick={() => downloadMedia(post.mediaURL, post.mediaType)}\n                style={{ position:'absolute', top:8, right:8, width:34, height:34, borderRadius:'50%', background:'rgba(0,0,0,.5)', border:'none', cursor:'pointer', color:'white', display:'flex', alignItems:'center', justifyContent:'center' }}>\n                <HiDownload size={16}/>\n              </button>\n            </div>\n          )}\n        </div>\n        )}\n\n        {/* Reaction count */}\n        {total>0&&(\n          <div style={{ padding:'0 16px 10px', cursor:'pointer', display:'flex', gap:6, flexWrap:'wrap', alignItems:'center' }} onClick={openRM}>\n            {Object.entries(rc).map(([e,c]) => <span key={e} style={{ background:'#E4E6EB', borderRadius:12, padding:'3px 10px', fontSize:13 }}>{e} {c}</span>)}\n            <span style={{ fontSize:12, color:'#65676B' }}>\u00b7 {total} {t('reactions')} \u2014 voir qui</span>\n          </div>\n        )}\n\n        {/* Actions */}\n        <div style={{ borderTop:'1px solid #E4E6EB', padding:'8px 16px', display:'flex', gap:4 }}>\n          <div style={{ position:'relative' }}>\n            <button onClick={() => setShowReact(p=>!p)} style={{ display:'flex', alignItems:'center', gap:4, background:'none', border:'none', cursor:'pointer', color:myR?'#1877F2':'#65676B', fontSize:13, padding:'6px 12px', borderRadius:20, fontWeight:500 }}>\n              {myR?<span style={{ fontSize:17 }}>{myR}</span>:<HiOutlineHeart size={19}/>}{total>0&&<span>{total}</span>}\n            </button>\n            {showReactions&&<div style={{ position:'absolute', bottom:'110%', left:0, background:'white', borderRadius:30, padding:'8px 12px', display:'flex', gap:6, boxShadow:'0 4px 20px rgba(0,0,0,.15)', zIndex:10, border:'1px solid #E4E6EB' }}>\n              {REACTIONS.map(e=><button key={e} onClick={() => reactToPost(e)} style={{ background:'none', border:'none', cursor:'pointer', fontSize:22 }}>{e}</button>)}\n            </div>}\n          </div>\n          <button style={{ display:'flex', alignItems:'center', gap:4, background:'none', border:'none', cursor:'pointer', color:'#1877F2', fontSize:13, padding:'6px 12px', borderRadius:20 }}><HiChat size={19}/>{post.comments?.length||0}</button>\n          <button onClick={sharePost} style={{ display:'flex', alignItems:'center', gap:4, background:'none', border:'none', cursor:'pointer', color:'#65676B', fontSize:13, padding:'6px 12px', borderRadius:20 }}><HiShare size={19}/></button>\n        </div>\n\n        {/* Comments */}\n        <div style={{ padding:'0 16px 16px', borderTop:'1px solid #E4E6EB' }}>\n          <p style={{ fontWeight:700, fontSize:14, marginTop:10, marginBottom:12 }}>Commentaires ({post.comments?.length||0})</p>\n\n          {post.comments?.map(c => (\n            <div key={c.id} style={{ display:'flex', gap:8, marginBottom:12 }}>\n              <img src={c.authorPhoto||`https://ui-avatars.com/api/?name=${encodeURIComponent(c.authorName||'U')}&background=1877F2&color=fff`} alt=\"\" className=\"avatar\" style={{ width:32, height:32, flexShrink:0, cursor:'pointer' }} onClick={() => navigate(`/profile/${c.uid}`)}/>\n              <div style={{ background:'#F0F2F5', borderRadius:12, padding:'8px 12px', flex:1 }}>\n                <p style={{ fontWeight:700, fontSize:13 }}>{c.authorName}{c.authorIsVip&&<VIPBadge/>}</p>\n                {c.text&&<p style={{ fontSize:13, lineHeight:1.5, marginTop:2 }}>{c.text}</p>}\n                {c.mediaURL&&<div style={{ marginTop:6 }}>{c.mediaType==='image'?<img src={c.mediaURL} alt=\"\" style={{ maxWidth:200, borderRadius:8 }}/>:<video src={c.mediaURL} controls style={{ maxWidth:200, borderRadius:8 }}/>}</div>}\n                <p style={{ fontSize:10, color:'#65676B', marginTop:4 }}>{c.createdAt?timeAgo(c.createdAt):''}</p>\n                <div style={{ display:'flex', gap:10, marginTop:4 }}>\n                  <button onClick={() => setReplyTo(c.authorName)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', fontSize:11, display:'flex', alignItems:'center', gap:3 }}><HiReply size={11}/> R\u00e9pondre</button><button onClick={() => setCmtReactPicker(p=>p===c.id?null:c.id)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', fontSize:11 }}>{c.reactions?.[currentUser.uid]||'\ud83d\ude0a'} {Object.keys(c.reactions||{}).length||''}</button>{cmtReactPicker===c.id&&<div style={{ display:'flex', gap:4, background:'white', borderRadius:20, padding:'4px 8px', boxShadow:'0 2px 12px rgba(0,0,0,.15)' }}>{['\u2764\ufe0f','\ud83d\ude02','\ud83d\ude2e','\ud83d\ude22','\ud83d\udc4d','\ud83d\udd25'].map(em=><span key={em} onClick={()=>reactToCmt(c.id,em)} style={{ fontSize:18, cursor:'pointer' }}>{em}</span>)}</div>}\n                  {c.uid===currentUser.uid && (\n                    <button onClick={() => setEditCmt({cmt:c,text:c.text})} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', fontSize:11, display:'flex', alignItems:'center', gap:3 }}><HiPencil size={11}/> Modifier</button>\n                  )}\n                  {(c.uid===currentUser.uid||post.uid===currentUser.uid) && (\n                    <button onClick={() => deleteCmt(c)} style={{ background:'none', border:'none', cursor:'pointer', color:'#FF2D8D', fontSize:11, display:'flex', alignItems:'center', gap:3 }}><HiTrash size={11}/> Supprimer</button>\n                  )}\n                </div>\n              </div>\n            </div>\n          ))}\n\n          {replyTo&&(\n            <div style={{ display:'flex', alignItems:'center', gap:6, marginBottom:8, background:'#F0F2F5', padding:'6px 10px', borderRadius:10 }}>\n              <HiReply size={14} color=\"#1877F2\"/>\n              <span style={{ fontSize:12, color:'#65676B' }}>R\u00e9pondre \u00e0 <strong>{replyTo}</strong></span>\n              <button onClick={() => setReplyTo(null)} style={{ marginLeft:'auto', background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={14}/></button>\n            </div>\n          )}\n\n          {commentMedia&&(\n            <div style={{ position:'relative', marginBottom:8, display:'inline-block' }}>\n              {commentMedia.type==='image'?<img src={commentMedia.preview} alt=\"\" style={{ maxWidth:130, borderRadius:8 }}/>:<video src={commentMedia.preview} style={{ maxWidth:130, borderRadius:8 }}/>}\n              <button onClick={() => setCmtMedia(null)} style={{ position:'absolute', top:2, right:2, background:'rgba(0,0,0,.5)', border:'none', borderRadius:'50%', width:20, height:20, cursor:'pointer', color:'white', fontSize:10, display:'flex', alignItems:'center', justifyContent:'center' }}>\u2715</button>\n            </div>\n          )}\n\n          <div style={{ display:'flex', gap:8, alignItems:'center', marginTop:10 }}>\n            <img src={userProfile?.photoURL||`https://ui-avatars.com/api/?name=${encodeURIComponent(userProfile?.fullName||'U')}&background=1877F2&color=fff`} alt=\"\" className=\"avatar\" style={{ width:32, height:32, flexShrink:0 }}/>\n            <input className=\"input\" placeholder={replyTo?`R\u00e9pondre \u00e0 ${replyTo}...`:t('writeComment')} value={commentText} onChange={e=>setCmtText(e.target.value)} onKeyDown={e=>e.key==='Enter'&&addComment()} style={{ flex:1, padding:'8px 12px', fontSize:13 }}/>\n            <input ref={cPhotoRef} type=\"file\" accept=\"image/*\" style={{ display:'none' }} onChange={e=>{const f=e.target.files[0];if(f)setCmtMedia({file:f,type:'image',preview:URL.createObjectURL(f)});}}/>\n            <input ref={cVideoRef} type=\"file\" accept=\"video/*\" style={{ display:'none' }} onChange={e=>{const f=e.target.files[0];if(f)setCmtMedia({file:f,type:'video',preview:URL.createObjectURL(f)});}}/>\n            <button onClick={() => cPhotoRef.current?.click()} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', padding:4 }}><HiPhotograph size={20}/></button>\n            <button onClick={() => cVideoRef.current?.click()} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', padding:4 }}><HiVideoCamera size={20}/></button>\n            <button onClick={addComment} style={{ background:'linear-gradient(135deg,#FF2D8D,#FF7AB8)', border:'none', borderRadius:'50%', width:36, height:36, cursor:'pointer', color:'white', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>\u27a4</button>\n          </div>\n        </div>\n      </div>\n\n      {viewerState && post && (\n        <MediaViewer\n          post={post}\n          startIndex={viewerState.index}\n          onClose={() => setViewerState(null)}\n          currentUser={currentUser}\n          userProfile={userProfile}\n          navigate={navigate}\n          myR={post.reactions?.[currentUser.uid]}\n          rc={(() => { const c={}; Object.values(post.reactions||{}).forEach(e=>{c[e]=(c[e]||0)+1;}); return c; })()}\n          total={Object.keys(post.reactions||{}).length}\n          onReact={reactToPost}\n          onOpenReactionModal={openRM}\n          onDownload={(url) => downloadMedia(url, post.mediaType || 'image')}\n          onShare={sharePost}\n          onSubmitComment={submitViewerComment}\n          onReactCmt={reactToCmt}\n          onDeleteCmt={deleteCmt}\n          VIPBadge={VIPBadge}\n        />\n      )}\n      {shareModalOpen && <ShareModal post={post} onClose={() => setShareModalOpen(false)} />}\n    </div>\n  );\n}\n";

const fs = require('fs');
